-- ----------------------------------------------------------------------------
-- vw_agents: Human and software agents that create, modify, approve, or execute procedural knowledge. Maps to prov:Agent.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_agents CASCADE;
CREATE VIEW vw_agents WITH (security_invoker = ON) AS
SELECT
  t.agent_id,                                                                   -- Stored logical identifier for one Agents row.
  calc_agents_name(t.agent_id) AS name,                                         -- Human-readable calculated display alias for the Agents row.
  t.display_name,                                                               -- Agent's human-readable name.
  t.agent_kind,                                                                 -- Human, AIAgent, AutomatedPipeline, Organization, or another explicit agent category.
  t.organization,                                                               -- Organization to which the agent belongs.
  t.contact_address,                                                            -- Contact address when applicable.
  t.version_or_employment_key,                                                  -- Model version, pipeline release, or employment assignment key.
  calc_agents_count_of_current_role_assignments(t.agent_id) AS count_of_current_role_assignments,-- How many role assignments this agent currently holds. Counts only CURRENT assignments via the CurrentAgentKey echo — counting all assignments would report a departed agent as engaged forever.
  calc_agents_is_still_engaged(t.agent_id) AS is_still_engaged,                 -- TRUE when this agent currently holds at least one role in the organization.
  calc_agents_decision_count(t.agent_id) AS decision_count,                     -- Total decisions this agent has recorded.
  calc_agents_overridden_decision_count(t.agent_id) AS overridden_decision_count,-- Decisions by this agent that a human corrected or reversed.
  calc_agents_override_rate_percent(t.agent_id) AS override_rate_percent,       -- Percentage of this agent's decisions that were overridden by a human.
  calc_agents_is_non_human(t.agent_id) AS is_non_human,                         -- TRUE when this agent is an AI agent or an automated pipeline.
  calc_agents_boundary_violation_count(t.agent_id) AS boundary_violation_count, -- Number of decisions by this agent that violated an authority boundary.
  calc_agents_is_operating_outside_boundary(t.agent_id) AS is_operating_outside_boundary,-- TRUE when this agent has made at least one decision an authority boundary forbids.
  calc_agents_draft_decision_count(t.agent_id) AS draft_decision_count,         -- Number of drafting decisions this agent has made.
  calc_agents_overridden_draft_count(t.agent_id) AS overridden_draft_count,     -- Number of this agent's drafting decisions a human corrected or reversed.
  calc_agents_draft_rewrite_rate_percent(t.agent_id) AS draft_rewrite_rate_percent,-- Percentage of this agent's drafting output that a human rewrote.
  t.semantic_type_iri                                                           -- Exact semantic type IRI used when projecting the agent.
FROM agents t;

-- ----------------------------------------------------------------------------
-- vw_roles: Stable organizational functions separated from the agents that currently fill them. Maps to pro:Role.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_roles CASCADE;
CREATE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,                                                                    -- Stored logical identifier for one Roles row.
  calc_roles_name(t.role_id) AS name,                                           -- Human-readable calculated display alias for the Roles row.
  t.label,                                                                      -- Human-readable role label.
  t.organization,                                                               -- Organization that owns the role.
  t.current_agent,                                                              -- Current agent filling the role; history is retained in RoleAssignments.
  calc_roles_current_agent_kind(t.role_id) AS current_agent_kind,               -- Agent category of the current role filler.
  t.responsibility,                                                             -- Accountability and responsibility assigned to the role.
  calc_roles_active_assignment_count(t.role_id) AS active_assignment_count,     -- Total number of assignment rows ever recorded against this role.
  calc_roles_currently_covered_assignment_count(t.role_id) AS currently_covered_assignment_count,-- Number of assignment rows for this role that are in force right now.
  calc_roles_has_no_current_holder(t.role_id) AS has_no_current_holder,         -- TRUE when no assignment currently covers this role — the role is uncovered.
  calc_roles_count_of_awaited_decisions(t.role_id) AS count_of_awaited_decisions,-- How many change requests name this role as the deciding authority.
  t.current_assignment,                                                         -- The RoleAssignments id of the assignment by which this role is currently held. Deliberately a raw identifier, not a relationship: RoleAssignments already points at Roles, so an FK back would make the two mutually dependent and this rulebook must stay acyclic.
  calc_roles_current_assignment_valid_from(t.role_id) AS current_assignment_valid_from,-- Start of the currently-in-force assignment for this role.
  calc_roles_is_non_human_held(t.role_id) AS is_non_human_held,                 -- TRUE when the role's current agent is an AI agent or automated pipeline.
  calc_roles_is_ungoverned_non_human_role(t.role_id) AS is_ungoverned_non_human_role,-- TRUE when a role is pointed at a non-human agent but has no assignment row granting it.
  t.semantic_type_iri                                                           -- Exact semantic type IRI for the role.
FROM roles t;

-- ----------------------------------------------------------------------------
-- vw_role_assignments: Time-bounded records of agents holding roles. Maps to pro:RoleInTime and preserves assignment history instead of overwriting it.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_role_assignments CASCADE;
CREATE VIEW vw_role_assignments WITH (security_invoker = ON) AS
SELECT
  t.role_assignment_id,                                                         -- Stored logical identifier for one RoleAssignments row.
  calc_role_assignments_name(t.role_assignment_id) AS name,                     -- Human-readable calculated display alias for the RoleAssignments row.
  t.role,                                                                       -- Role held during the assignment.
  t.agent,                                                                      -- Agent holding the role.
  t.valid_from,                                                                 -- Start of the assignment's valid-time interval.
  t.valid_to,                                                                   -- End of the assignment's valid-time interval; null means open-ended.
  t.reason,                                                                     -- Rationale for the assignment or reassignment.
  t.status,                                                                     -- Active, Superseded, Planned, or Revoked.
  t.evaluation_context,                                                         -- The evaluation context this assignment's currency is judged under.
  calc_role_assignments_as_of_instant(t.role_assignment_id) AS as_of_instant,   -- The evaluation instant this assignment's currency is judged against.
  calc_role_assignments_is_current(t.role_assignment_id) AS is_current,         -- TRUE when the assignment is valid now.
  calc_role_assignments_current_agent_key(t.role_assignment_id) AS current_agent_key,-- Echoes the Agent id only while this assignment is current; empty otherwise. Lets a parent count CURRENT assignments with a single-criterion COUNTIFS, which is the only shape this transpiler translates correctly.
  calc_role_assignments_is_currently_valid(t.role_assignment_id) AS is_currently_valid,-- TRUE when this role assignment is active and has not lapsed.
  calc_role_assignments_agent_role_key(t.role_assignment_id) AS agent_role_key, -- Composite agent+role key, emitted only for currently-valid assignments.
  calc_role_assignments_has_departed(t.role_assignment_id) AS has_departed,     -- TRUE when this role assignment has ended — the agent no longer holds the role.
  calc_role_assignments_covers_now(t.role_assignment_id) AS covers_now,         -- TRUE when this assignment is both status-Active and inside its valid-time window right now.
  calc_role_assignments_role_when_covering(t.role_assignment_id) AS role_when_covering,-- Echoes the role id when this assignment is currently in force, blank otherwise.
  calc_role_assignments_agent_kind(t.role_assignment_id) AS agent_kind,         -- Whether the agent holding this assignment is Human, AIAgent, or AutomatedPipeline.
  calc_role_assignments_is_non_human_assignment(t.role_assignment_id) AS is_non_human_assignment,-- TRUE when this assignment places a non-human agent into the role.
  t.supersedes_assignment,                                                      -- The assignment this one replaced, if any.
  calc_role_assignments_predecessor_agent_kind(t.role_assignment_id) AS predecessor_agent_kind,-- Agent kind of the assignment this one superseded.
  calc_role_assignments_is_human_to_non_human_handover(t.role_assignment_id) AS is_human_to_non_human_handover,-- TRUE when this assignment handed a role from a human to a non-human agent.
  t.approving_authority_role,                                                   -- Role that approved this assignment.
  t.authorizing_change_request,                                                 -- Change request under which this assignment was approved.
  calc_role_assignments_is_unauthorized_non_human_assignment(t.role_assignment_id) AS is_unauthorized_non_human_assignment,-- TRUE when a non-human agent holds a role with no recorded approving authority or no authorizing change request.
  calc_role_assignments_decision_count(t.role_assignment_id) AS decision_count, -- Decisions made under this assignment.
  calc_role_assignments_overridden_decision_count(t.role_assignment_id) AS overridden_decision_count,-- Decisions made under this assignment that a human corrected or reversed.
  calc_role_assignments_override_rate_percent(t.role_assignment_id) AS override_rate_percent,-- Percentage of decisions under this assignment that a human overrode.
  calc_role_assignments_predecessor_override_rate_percent(t.role_assignment_id) AS predecessor_override_rate_percent,-- Override rate of the assignment this one superseded.
  calc_role_assignments_quality_regressed_vs_predecessor(t.role_assignment_id) AS quality_regressed_vs_predecessor,-- TRUE when this assignment is overridden by humans more often than the assignment it replaced.
  t.semantic_type_iri                                                           -- Exact class IRI for the assignment event.
FROM role_assignments t;

