-- ----------------------------------------------------------------------------
-- vw_procedure_versions: Versioned procedure specifications. Maps to pko:Procedure plus DCAT version relations and PKO versionNumber/newVersionMotivation/changelogDescription.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_versions CASCADE;
CREATE VIEW vw_procedure_versions WITH (security_invoker = ON) AS
SELECT
  t.procedure_version_id,                                                       -- Stored logical identifier for one ProcedureVersions row.
  calc_procedure_versions_name(t.procedure_version_id) AS name,                 -- Human-readable calculated display alias for the ProcedureVersions row.
  t.procedure,                                                                  -- Abstract procedure of which this is a version.
  t.version_number,                                                             -- Version number; maps to pko:versionNumber.
  t.title,                                                                      -- Version-specific title.
  t.status,                                                                     -- PKO procedure status individual: Draft, Validation, Approval, Approved, Deprecated, or Archived.
  t.issued_at,                                                                  -- Issue timestamp; maps to dcterms:issued.
  t.modified_at,                                                                -- Last semantic modification; maps to dcterms:modified.
  t.created_by_agent,                                                           -- Agent that created the version; maps to dcterms:creator.
  t.modified_by_agent,                                                          -- Agent that last modified the version; maps to pko:wasModifiedBy.
  t.new_version_motivation,                                                     -- Reason for the new version; maps to pko:newVersionMotivation.
  t.changelog_description,                                                      -- Semantic change description; maps to pko:changelogDescription.
  t.is_current,                                                                 -- TRUE when this is the current version.
  calc_procedure_versions_count_of_steps(t.procedure_version_id) AS count_of_steps,-- Number of steps in this version.
  calc_procedure_versions_count_of_open_knowledge_gaps(t.procedure_version_id) AS count_of_open_knowledge_gaps,-- Open knowledge gaps for this version.
  calc_procedure_versions_is_ready_for_execution(t.procedure_version_id) AS is_ready_for_execution,-- TRUE when approved, populated, and free of blocking knowledge gaps.
  calc_procedure_versions_specified_step_count(t.procedure_version_id) AS specified_step_count,-- How many steps the specification defines for this version.
  calc_procedure_versions_overdue_review_count(t.procedure_version_id) AS overdue_review_count,-- How many reviews of this procedure version are past due.
  calc_procedure_versions_open_change_request_count(t.procedure_version_id) AS open_change_request_count,-- How many change requests are open against this version.
  calc_procedure_versions_open_high_severity_gap_count(t.procedure_version_id) AS open_high_severity_gap_count,-- How many high-severity knowledge gaps are open against this version.
  calc_procedure_versions_is_fit_to_execute(t.procedure_version_id) AS is_fit_to_execute,-- TRUE when this version is approved, current on review, and carries no open change request or high-severity gap.
  calc_procedure_versions_steward_review_cadence_days(t.procedure_version_id) AS steward_review_cadence_days,-- The review cadence promised by this version's stewardship assignment, in days. Summed because a version has at most one active steward; this is the hop that lets ReviewEvents resolve the promise via a primary-key match.
  calc_procedure_versions_count_of_stewardship_assignments(t.procedure_version_id) AS count_of_stewardship_assignments,-- How many stewardship assignments of any vintage point at this version.
  calc_procedure_versions_has_any_steward(t.procedure_version_id) AS has_any_steward,-- TRUE if any stewardship assignment has ever named this version.
  calc_procedure_versions_is_live(t.procedure_version_id) AS is_live,           -- TRUE when this version is in a state where somebody could execute it.
  calc_procedure_versions_is_unstewarded(t.procedure_version_id) AS is_unstewarded,-- TRUE when no stewardship assignment names this version.
  calc_procedure_versions_is_live_and_unstewarded(t.procedure_version_id) AS is_live_and_unstewarded,-- TRUE when an executable version has nobody accountable for keeping it healthy.
  calc_procedure_versions_count_of_open_blocking_gaps(t.procedure_version_id) AS count_of_open_blocking_gaps,-- How many open blocking gaps stand against this version.
  calc_procedure_versions_has_open_blocking_gap(t.procedure_version_id) AS has_open_blocking_gap,-- TRUE when at least one open blocking gap stands against this version.
  calc_procedure_versions_is_live_with_blocking_gap(t.procedure_version_id) AS is_live_with_blocking_gap,-- TRUE when an executable version carries an unresolved blocking knowledge gap.
  calc_procedure_versions_should_not_be_executable(t.procedure_version_id) AS should_not_be_executable,-- TRUE when the model says this version is ready to execute while a blocking gap is open against it.
  calc_procedure_versions_count_of_unapproved_reliance_fragments(t.procedure_version_id) AS count_of_unapproved_reliance_fragments,-- How many unapproved claims this version is relying on.
  calc_procedure_versions_runs_on_unapproved_knowledge(t.procedure_version_id) AS runs_on_unapproved_knowledge,-- TRUE when this version depends on at least one claim the knowledge authority has not approved.
  calc_procedure_versions_count_of_overdue_gaps(t.procedure_version_id) AS count_of_overdue_gaps,-- How many acknowledged unknowns against this version have outlived their tolerance.
  calc_procedure_versions_count_of_change_requests(t.procedure_version_id) AS count_of_change_requests,-- How many change requests have ever been raised against this version.
  calc_procedure_versions_count_of_review_events(t.procedure_version_id) AS count_of_review_events,-- How many review events have ever been recorded against this version.
  calc_procedure_versions_has_governance_record(t.procedure_version_id) AS has_governance_record,-- TRUE when at least one change request or review event exists for this version.
  calc_procedure_versions_days_since_modified(t.procedure_version_id) AS days_since_modified,-- Days since this version's content was last changed.
  calc_procedure_versions_days_since_last_review(t.procedure_version_id) AS days_since_last_review,-- Days since the most recent review of this version.
  calc_procedure_versions_was_modified_since_last_review(t.procedure_version_id) AS was_modified_since_last_review,-- TRUE when the version was edited more recently than it was reviewed.
  calc_procedure_versions_modifier_is_authority(t.procedure_version_id) AS modifier_is_authority,-- The kind of agent that last modified this version.
  calc_procedure_versions_has_unwitnessed_change(t.procedure_version_id) AS has_unwitnessed_change,-- TRUE when a live version's current content postdates every review it has had.
  calc_procedure_versions_count_of_stale_fragments(t.procedure_version_id) AS count_of_stale_fragments,-- How many supporting claims have outlived this version's review cadence.
  calc_procedure_versions_knowledge_is_staler_than_cadence(t.procedure_version_id) AS knowledge_is_staler_than_cadence,-- TRUE when this version rests on at least one claim older than its own review cadence.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedure_versions t;

-- ----------------------------------------------------------------------------
-- vw_procedure_version_links: Directed links between versioned procedures. Maps to dcat:previousVersion/dcat:hasVersion and pko:nextVersion.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_version_links CASCADE;
CREATE VIEW vw_procedure_version_links WITH (security_invoker = ON) AS
SELECT
  t.procedure_version_link_id,                                                  -- Stored logical identifier for one ProcedureVersionLinks row.
  calc_procedure_version_links_name(t.procedure_version_link_id) AS name,       -- Human-readable calculated display alias for the ProcedureVersionLinks row.
  t.previous_procedure_version,                                                 -- Earlier version.
  t.next_procedure_version,                                                     -- Later version.
  t.relation_iri,                                                               -- Exact version relation IRI.
  t.change_summary                                                              -- Summary of semantic change across the edge.
FROM procedure_version_links t;

-- ----------------------------------------------------------------------------
-- vw_procedure_status_changes: Lifecycle events that move a procedure version between PKO statuses. Maps to pko:ChangeOfStatus, fromStatus, toStatus, and prov:atTime.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_status_changes CASCADE;
CREATE VIEW vw_procedure_status_changes WITH (security_invoker = ON) AS
SELECT
  t.procedure_status_change_id,                                                 -- Stored logical identifier for one ProcedureStatusChanges row.
  calc_procedure_status_changes_name(t.procedure_status_change_id) AS name,     -- Human-readable calculated display alias for the ProcedureStatusChanges row.
  t.procedure_version,                                                          -- Procedure version whose status changed.
  t.from_status,                                                                -- Previous PKO status.
  t.to_status,                                                                  -- New PKO status.
  t.changed_at,                                                                 -- Time of change; maps to prov:atTime.
  t.changed_by_agent,                                                           -- Agent responsible for the change.
  t.motivation,                                                                 -- Reason for changing status.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedure_status_changes t;

-- ----------------------------------------------------------------------------
-- vw_steps: Version-scoped units of work. Atomic steps map to pplan:Step; composite steps map to pplan:MultiStep. The specification is never conflated with execution.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_steps CASCADE;
CREATE VIEW vw_steps WITH (security_invoker = ON) AS
SELECT
  t.step_id,                                                                    -- Stored logical identifier for one Steps row.
  calc_steps_name(t.step_id) AS name,                                           -- Human-readable calculated display alias for the Steps row.
  t.procedure_version,                                                          -- Procedure version containing the step; maps to pko:hasStep/pplan:isStepOfPlan.
  t.step_number,                                                                -- Stable sequence label; maps to pko:stepNumber.
  t.title,                                                                      -- Human-readable step title.
  t.step_kind,                                                                  -- Atomic or MultiStep.
  t.assigned_role,                                                              -- Role responsible for the step.
  calc_steps_assigned_role_label(t.step_id) AS assigned_role_label,             -- Resolved role label.
  calc_steps_assigned_agent_kind(t.step_id) AS assigned_agent_kind,             -- Current role-filler category.
  t.instruction,                                                                -- Normative step instruction.
  t.expected_duration_minutes,                                                  -- Expected duration represented as an OWL-Time duration in semantic projections.
  t.expertise_level,                                                            -- PKO expertise level: Junior, Senior, Expert, or Master.
  t.requires_human_confirmation,                                                -- TRUE when a human must confirm the step; maps to pko:wasConfirmedBy at execution.
  calc_steps_blocking_requirement_count(t.step_id) AS blocking_requirement_count,-- How many blocking requirements the specification attaches to this step.
  calc_steps_stale_binding_count(t.step_id) AS stale_binding_count,             -- How many operational bindings for this step are currently outside their freshness SLA.
  calc_steps_authoritative_stale_count(t.step_id) AS authoritative_stale_count, -- How many authoritative bindings for this step are currently stale.
  calc_steps_available_exception_count(t.step_id) AS available_exception_count, -- How many active exceptions the specification defines for this step.
  calc_steps_declared_verification_count(t.step_id) AS declared_verification_count,-- How many verifications the specification declares for this step.
  calc_steps_is_preparation_step(t.step_id) AS is_preparation_step,             -- TRUE for steps whose assigned role produces the work product rather than reviewing it.
  calc_steps_is_approval_step(t.step_id) AS is_approval_step,                   -- TRUE for steps whose assigned role is an approval authority.
  calc_steps_stale_authoritative_binding_count(t.step_id) AS stale_authoritative_binding_count,-- Number of authoritative bindings for this step that are past their freshness SLA.
  calc_steps_inputs_are_fresh(t.step_id) AS inputs_are_fresh,                   -- TRUE when no authoritative binding for this step is stale.
  calc_steps_is_software_assigned(t.step_id) AS is_software_assigned,           -- TRUE when this step is specified to be performed by software rather than a person.
  calc_steps_is_human_approval_gate(t.step_id) AS is_human_approval_gate,       -- TRUE for the steps that exist specifically to place a human commitment between drafting and delivery.
  calc_steps_gate_held_by_human(t.step_id) AS gate_held_by_human,               -- TRUE when a designated approval gate is in fact assigned to a human role.
  calc_steps_binding_boundary_count(t.step_id) AS binding_boundary_count,       -- Number of authority boundaries currently binding at this step.
  calc_steps_assigned_role_is_ungoverned(t.step_id) AS assigned_role_is_ungoverned,-- Whether this step's assigned role is a non-human role with no governing assignment.
  calc_steps_unusable_binding_count(t.step_id) AS unusable_binding_count,       -- Number of bindings at this step that are unapproved or stale.
  calc_steps_all_sources_usable(t.step_id) AS all_sources_usable,               -- TRUE when every binding at this step is an approved, fresh source.
  t.semantic_type_iri                                                           -- Exact P-Plan class IRI.
FROM steps t;

-- ----------------------------------------------------------------------------
-- vw_step_transitions: Directed control-flow edges represented as first-class pko:Transition instances with fromStep/toStep and next/alternative/fallback semantics.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_transitions CASCADE;
CREATE VIEW vw_step_transitions WITH (security_invoker = ON) AS
SELECT
  t.step_transition_id,                                                         -- Stored logical identifier for one StepTransitions row.
  calc_step_transitions_name(t.step_transition_id) AS name,                     -- Human-readable calculated display alias for the StepTransitions row.
  t.procedure_version,                                                          -- Procedure version whose control flow owns the transition.
  t.from_step,                                                                  -- Source step; maps to pko:fromStep.
  t.to_step,                                                                    -- Destination step; maps to pko:toStep.
  t.transition_kind,                                                            -- Next, Alternative, or Fallback.
  t.condition,                                                                  -- Condition under which the edge is taken.
  t.priority,                                                                   -- Evaluation priority when several outgoing edges exist.
  calc_step_transitions_is_recovery_path(t.step_transition_id) AS is_recovery_path,-- TRUE when this transition is a non-default path taken because something went wrong.
  calc_step_transitions_count_of_from_step_executions(t.step_transition_id) AS count_of_from_step_executions,-- How many times the step this transition leaves from has actually been executed.
  calc_step_transitions_count_of_to_step_executions(t.step_transition_id) AS count_of_to_step_executions,-- How many times the step this transition arrives at has actually been executed.
  calc_step_transitions_has_reachable_origin(t.step_transition_id) AS has_reachable_origin,-- TRUE when the origin step of this transition has been executed at least once.
  calc_step_transitions_has_reachable_target(t.step_transition_id) AS has_reachable_target,-- TRUE when the destination step of this transition has been executed at least once.
  calc_step_transitions_is_never_exercised(t.step_transition_id) AS is_never_exercised,-- TRUE when at least one end of this transition has never appeared in any step execution.
  calc_step_transitions_is_untested_recovery_path(t.step_transition_id) AS is_untested_recovery_path,-- TRUE for a Fallback or Alternative transition whose endpoints show no execution evidence.
  calc_step_transitions_count_of_observed_traversals(t.step_transition_id) AS count_of_observed_traversals,-- How many times this exact transition has actually been traversed.
  calc_step_transitions_has_been_traversed(t.step_transition_id) AS has_been_traversed,-- TRUE when this transition has been walked at least once.
  calc_step_transitions_is_unwalked_recovery_path(t.step_transition_id) AS is_unwalked_recovery_path,-- TRUE for a Fallback/Alternative transition with zero recorded traversals.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM step_transitions t;

-- ----------------------------------------------------------------------------
-- vw_actions: Human actions required by steps. Maps to pko:Action and pko:requiresAction.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_actions CASCADE;
CREATE VIEW vw_actions WITH (security_invoker = ON) AS
SELECT
  t.action_id,                                                                  -- Stored logical identifier for one Actions row.
  calc_actions_name(t.action_id) AS name,                                       -- Human-readable calculated display alias for the Actions row.
  t.label,                                                                      -- Action label.
  t.definition,                                                                 -- Normative definition of the action.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM actions t;

-- ----------------------------------------------------------------------------
-- vw_functions: Software or algorithmic functions required by steps. Maps to pko:Function and pko:requiresFunction.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_functions CASCADE;
CREATE VIEW vw_functions WITH (security_invoker = ON) AS
SELECT
  t.function_id,                                                                -- Stored logical identifier for one Functions row.
  calc_functions_name(t.function_id) AS name,                                   -- Human-readable calculated display alias for the Functions row.
  t.label,                                                                      -- Function label.
  t.definition,                                                                 -- Deterministic or AI-assisted behavior.
  t.implementation_key,                                                         -- Operational implementation or model key.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM functions t;

-- ----------------------------------------------------------------------------
-- vw_tools: Tools required to execute steps. Maps to m4ing:Tool and pko:requiresTool.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tools CASCADE;
CREATE VIEW vw_tools WITH (security_invoker = ON) AS
SELECT
  t.tool_id,                                                                    -- Stored logical identifier for one Tools row.
  calc_tools_name(t.tool_id) AS name,                                           -- Human-readable calculated display alias for the Tools row.
  t.label,                                                                      -- Tool label.
  t.purpose,                                                                    -- Operational purpose.
  t.semantic_type_iri                                                           -- Exact semantic class IRI.
FROM tools t;

-- ----------------------------------------------------------------------------
-- vw_step_actions: Many-to-many Step/Action semantics normalized into a first-class ERB junction table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_actions CASCADE;
CREATE VIEW vw_step_actions WITH (security_invoker = ON) AS
SELECT
  t.step_action_id,                                                             -- Stored logical identifier for one StepActions row.
  calc_step_actions_name(t.step_action_id) AS name,                             -- Human-readable calculated display alias for the StepActions row.
  t.step,                                                                       -- Step side of the relationship.
  t."action"                                                                    -- Action side of the relationship.
FROM step_actions t;

-- ----------------------------------------------------------------------------
-- vw_step_functions: Many-to-many Step/Function semantics normalized into an ERB junction table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_functions CASCADE;
CREATE VIEW vw_step_functions WITH (security_invoker = ON) AS
SELECT
  t.step_function_id,                                                           -- Stored logical identifier for one StepFunctions row.
  calc_step_functions_name(t.step_function_id) AS name,                         -- Human-readable calculated display alias for the StepFunctions row.
  t.step,                                                                       -- Step side of the relationship.
  t.function                                                                    -- Function side of the relationship.
FROM step_functions t;

-- ----------------------------------------------------------------------------
-- vw_step_tools: Many-to-many Step/Tool semantics normalized into an ERB junction table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_tools CASCADE;
CREATE VIEW vw_step_tools WITH (security_invoker = ON) AS
SELECT
  t.step_tool_id,                                                               -- Stored logical identifier for one StepTools row.
  calc_step_tools_name(t.step_tool_id) AS name,                                 -- Human-readable calculated display alias for the StepTools row.
  t.step,                                                                       -- Step side of the relationship.
  t.tool                                                                        -- Tool side of the relationship.
FROM step_tools t;

-- ----------------------------------------------------------------------------
-- vw_requirements: Normative requirements applied to procedures, steps, or transitions. Maps to pko:Requirement and pko:hasRequirement.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_requirements CASCADE;
CREATE VIEW vw_requirements WITH (security_invoker = ON) AS
SELECT
  t.requirement_id,                                                             -- Stored logical identifier for one Requirements row.
  calc_requirements_name(t.requirement_id) AS name,                             -- Human-readable calculated display alias for the Requirements row.
  t.label,                                                                      -- Requirement label.
  t.requirement_type,                                                           -- Controlled requirement type; maps to pko:hasRequirementType.
  t.statement,                                                                  -- Normative requirement statement.
  t.rationale,                                                                  -- Why the requirement exists.
  t.is_blocking,                                                                -- TRUE when unsatisfied requirement blocks execution or approval.
  calc_requirements_satisfaction_record_count(t.requirement_id) AS satisfaction_record_count,-- How many times this requirement has ever been evaluated against an execution.
  calc_requirements_step_binding_count(t.requirement_id) AS step_binding_count, -- How many steps the specification binds this requirement to.
  calc_requirements_is_bound_to_any_step(t.requirement_id) AS is_bound_to_any_step,-- TRUE when at least one step carries this requirement.
  calc_requirements_has_ever_been_evaluated(t.requirement_id) AS has_ever_been_evaluated,-- TRUE when this requirement has at least one satisfaction record in the model.
  calc_requirements_negative_outcome_count(t.requirement_id) AS negative_outcome_count,-- How many times this requirement has ever produced a less-than-satisfied outcome.
  calc_requirements_is_inoperative_control(t.requirement_id) AS is_inoperative_control,-- TRUE for a blocking requirement that is attached to a step in the specification but has never once been evaluated on any execution.
  calc_requirements_is_decorative_control(t.requirement_id) AS is_decorative_control,-- TRUE for a blocking requirement that is not attached to any step at all.
  t.has_computed_witness,                                                       -- Whether a computed predicate in this rulebook evaluates this requirement, as opposed to it being satisfied by human assertion only.
  t.witness_field_name,                                                         -- The fully-qualified Table.Field of the predicate that computes this requirement, when one exists.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM requirements t;

-- ----------------------------------------------------------------------------
-- vw_step_requirements: Many-to-many Step/Requirement semantics normalized into an ERB junction table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_requirements CASCADE;
CREATE VIEW vw_step_requirements WITH (security_invoker = ON) AS
SELECT
  t.step_requirement_id,                                                        -- Stored logical identifier for one StepRequirements row.
  calc_step_requirements_name(t.step_requirement_id) AS name,                   -- Human-readable calculated display alias for the StepRequirements row.
  t.step,                                                                       -- Step side of the relationship.
  t.requirement,                                                                -- Requirement side of the relationship.
  calc_step_requirements_requirement_is_blocking(t.step_requirement_id) AS requirement_is_blocking,-- Whether this spec-side step/requirement binding names a blocking control.
  calc_step_requirements_blocking_step_key(t.step_requirement_id) AS blocking_step_key,-- Echoes the Step id only when the bound requirement is blocking; empty otherwise.
  calc_step_requirements_step_when_blocking(t.step_requirement_id) AS step_when_blocking-- Echoes the step id when the bound requirement is blocking, blank otherwise.
FROM step_requirements t;

-- ----------------------------------------------------------------------------
-- vw_step_verifications: Verification definitions attached to steps. Maps to pko:StepVerification and pko:SignalVerification.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_verifications CASCADE;
CREATE VIEW vw_step_verifications WITH (security_invoker = ON) AS
SELECT
  t.step_verification_id,                                                       -- Stored logical identifier for one StepVerifications row.
  calc_step_verifications_name(t.step_verification_id) AS name,                 -- Human-readable calculated display alias for the StepVerifications row.
  t.step,                                                                       -- Step whose execution is verified; maps to pko:hasStepVerification.
  t.verification_kind,                                                          -- SignalVerification, ApprovalVerification, ProvenanceVerification, or another documented kind.
  t.signal_identifier,                                                          -- Signal or evidence key; maps to pko:signalIdentifier for signal verifications.
  t.expected_signal_value,                                                      -- Expected value; maps to pko:expectedSignalValue.
  t.instruction,                                                                -- How to verify the step.
  t.semantic_type_iri                                                           -- Exact PKO or extension class IRI.
FROM step_verifications t;

-- ----------------------------------------------------------------------------
-- vw_rationales: First-class rationale statements explaining why procedural commitments and design decisions exist. Explicit ERB-PKO extension, represented as prov:Entity/dcat:Resource in projections.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_rationales CASCADE;
CREATE VIEW vw_rationales WITH (security_invoker = ON) AS
SELECT
  t.rationale_id,                                                               -- Stored logical identifier for one Rationales row.
  calc_rationales_name(t.rationale_id) AS name,                                 -- Human-readable calculated display alias for the Rationales row.
  t.procedure_version,                                                          -- Version justified by the rationale.
  t.step,                                                                       -- Optional step justified by the rationale.
  t.title,                                                                      -- Rationale title.
  t.statement,                                                                  -- Reasoned explanation.
  t.status,                                                                     -- Draft, Reviewed, Approved, or Superseded.
  t.authority_role,                                                             -- Role authorized to approve the rationale.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM rationales t;

-- ----------------------------------------------------------------------------
-- vw_exceptions: Documented exceptions, fallbacks, and alternative handling. Aligns structurally with PKO fallback/alternative steps and requirements; the exception record itself is an ERB-PKO extension.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_exceptions CASCADE;
CREATE VIEW vw_exceptions WITH (security_invoker = ON) AS
SELECT
  t.exception_id,                                                               -- Stored logical identifier for one Exceptions row.
  calc_exceptions_name(t.exception_id) AS name,                                 -- Human-readable calculated display alias for the Exceptions row.
  t.procedure_version,                                                          -- Procedure version containing the exception.
  t.trigger_step,                                                               -- Step at which the exception becomes relevant.
  t.condition,                                                                  -- Exception condition.
  t.handling,                                                                   -- Required handling and guardrails.
  t.approval_role,                                                              -- Role that approves use of the exception.
  t.fallback_role,                                                              -- Role or function that executes fallback handling.
  t.status,                                                                     -- Active, Draft, Retired, or Superseded.
  calc_exceptions_active_exception_step_key(t.exception_id) AS active_exception_step_key,-- Echoes the TriggerStep id only for exceptions currently in Active status.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM exceptions t;

-- ----------------------------------------------------------------------------
-- vw_resources: Documents, datasets, APIs, templates, images, manuals, and operational records referenced by procedures. Maps to dcat:Resource.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_resources CASCADE;
CREATE VIEW vw_resources WITH (security_invoker = ON) AS
SELECT
  t.resource_id,                                                                -- Stored logical identifier for one Resources row.
  calc_resources_name(t.resource_id) AS name,                                   -- Human-readable calculated display alias for the Resources row.
  t.title,                                                                      -- Resource title; maps to dcterms:title.
  t.resource_kind,                                                              -- Document, Dataset, API, Template, OperationalRecord, Image, Video, or another declared type.
  t.external_uri,                                                               -- Resolvable or organization-internal resource identifier.
  t.created_at,                                                                 -- Creation time; maps to dcterms:created.
  t.modified_at,                                                                -- Modification time; maps to dcterms:modified.
  t.description,                                                                -- Resource description; maps to dcterms:description.
  t.approval_status,                                                            -- Approved, Draft, Deprecated, or Unvetted.
  calc_resources_is_approved_source(t.resource_id) AS is_approved_source,       -- TRUE when this resource is an approved source.
  t.semantic_type_iri                                                           -- Exact semantic class IRI.
FROM resources t;

-- ----------------------------------------------------------------------------
-- vw_procedure_resources: Links versioned procedures to supporting resources using PKO/dcterms provenance relations.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_resources CASCADE;
CREATE VIEW vw_procedure_resources WITH (security_invoker = ON) AS
SELECT
  t.procedure_resource_id,                                                      -- Stored logical identifier for one ProcedureResources row.
  calc_procedure_resources_name(t.procedure_resource_id) AS name,               -- Human-readable calculated display alias for the ProcedureResources row.
  t.procedure_version,                                                          -- Procedure version.
  t.resource,                                                                   -- Referenced or source resource.
  t.relation,                                                                   -- wasExtractedFrom, references, generated, used, or another declared relation.
  calc_procedure_resources_relation_iri(t.procedure_resource_id) AS relation_iri-- Exact semantic property IRI for the relation.
FROM procedure_resources t;

-- ----------------------------------------------------------------------------
-- vw_elicitation_sessions: Structured knowledge-elicitation events involving practitioners and knowledge engineers. Explicit ERB-PKO extension, modeled as prov:Activity.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_elicitation_sessions CASCADE;
CREATE VIEW vw_elicitation_sessions WITH (security_invoker = ON) AS
SELECT
  t.elicitation_session_id,                                                     -- Stored logical identifier for one ElicitationSessions row.
  calc_elicitation_sessions_name(t.elicitation_session_id) AS name,             -- Human-readable calculated display alias for the ElicitationSessions row.
  t.procedure_version,                                                          -- Procedure version whose knowledge was elicited.
  t.method,                                                                     -- Interview, shadowing, workshop, observation, document analysis, or another method.
  t.started_at,                                                                 -- Start time; maps to prov:startedAtTime.
  t.ended_at,                                                                   -- End time; maps to prov:endedAtTime.
  t.practitioner_agent,                                                         -- Domain practitioner providing knowledge.
  t.facilitator_agent,                                                          -- Person facilitating elicitation.
  t.summary,                                                                    -- What was learned and captured.
  t.status,                                                                     -- Draft, Reviewed, Approved, or Rejected.
  calc_elicitation_sessions_days_since_elicited(t.elicitation_session_id) AS days_since_elicited,-- Days elapsed since this elicitation session concluded.
  calc_elicitation_sessions_is_single_witness_method(t.elicitation_session_id) AS is_single_witness_method,-- TRUE when this session captured one practitioner's account rather than a group's.
  calc_elicitation_sessions_practitioner_is_still_engaged(t.elicitation_session_id) AS practitioner_is_still_engaged,-- Whether the practitioner whose knowledge this session captured still holds a role here.
  t.semantic_type_iri                                                           -- Class IRI used in semantic projection.
FROM elicitation_sessions t;

-- ----------------------------------------------------------------------------
-- vw_knowledge_fragments: Explicit records of tacit, implicit, explicit, and situated procedural knowledge. This is an ERB-PKO extension represented as provenance-bearing dcat:Resource instances.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_knowledge_fragments CASCADE;
CREATE VIEW vw_knowledge_fragments WITH (security_invoker = ON) AS
SELECT
  t.knowledge_fragment_id,                                                      -- Stored logical identifier for one KnowledgeFragments row.
  calc_knowledge_fragments_name(t.knowledge_fragment_id) AS name,               -- Human-readable calculated display alias for the KnowledgeFragments row.
  t.procedure_version,                                                          -- Procedure version informed by the fragment.
  t.step,                                                                       -- Optional step to which the fragment applies.
  t.knowledge_form,                                                             -- Tacit, Implicit, Explicit, SituatedJudgment, LessonLearned, or another declared form.
  t.statement,                                                                  -- Captured knowledge statement.
  t.elicitation_session,                                                        -- Optional elicitation session that produced the fragment.
  t.source_agent,                                                               -- Practitioner or source agent.
  t.confidence,                                                                 -- Low, Medium, or High confidence.
  t.valid_from,                                                                 -- Start of the fragment's valid-time interval.
  t.valid_to,                                                                   -- End of the fragment's valid-time interval.
  t.status,                                                                     -- Draft, Reviewed, Approved, Rejected, or Superseded.
  t.owner_role,                                                                 -- Role accountable for maintaining the fragment.
  t.evaluation_context,                                                         -- The evaluation context this row's time-dependent witnesses are judged under.
  calc_knowledge_fragments_as_of_instant(t.knowledge_fragment_id) AS as_of_instant,-- The evaluation instant this row's time-dependent witnesses are judged against.
  calc_knowledge_fragments_is_currently_valid(t.knowledge_fragment_id) AS is_currently_valid,-- TRUE when the fragment is approved and valid now.
  calc_knowledge_fragments_source_agent_is_still_engaged(t.knowledge_fragment_id) AS source_agent_is_still_engaged,-- Whether the agent who is the source of this claim still holds a role here.
  calc_knowledge_fragments_source_agent_kind(t.knowledge_fragment_id) AS source_agent_kind,-- Whether the source of this claim is a Human, an AIAgent, or an AutomatedPipeline.
  calc_knowledge_fragments_has_human_source(t.knowledge_fragment_id) AS has_human_source,-- TRUE when the claim originates from a human practitioner rather than software.
  calc_knowledge_fragments_has_orphaned_provenance(t.knowledge_fragment_id) AS has_orphaned_provenance,-- TRUE when we still rely on this claim but the agent who gave it to us no longer holds a role here.
  calc_knowledge_fragments_is_undefendable_tacit_claim(t.knowledge_fragment_id) AS is_undefendable_tacit_claim,-- TRUE when an orphaned claim is of a kind that lives in a person's head rather than in a document.
  calc_knowledge_fragments_is_approved(t.knowledge_fragment_id) AS is_approved, -- TRUE when this claim has passed knowledge-authority approval.
  calc_knowledge_fragments_is_within_validity_window(t.knowledge_fragment_id) AS is_within_validity_window,-- TRUE when this claim's stated validity window contains the present moment.
  calc_knowledge_fragments_is_relied_upon(t.knowledge_fragment_id) AS is_relied_upon,-- TRUE when this claim is attached to a specific step and is inside its validity window — i.e. it is operationally in play.
  calc_knowledge_fragments_step_procedure_version_status(t.knowledge_fragment_id) AS step_procedure_version_status,-- The procedure version owning the step this claim is attached to.
  calc_knowledge_fragments_is_attached_to_live_version(t.knowledge_fragment_id) AS is_attached_to_live_version,-- Whether the procedure version this claim belongs to is currently executable.
  calc_knowledge_fragments_is_unapproved_but_relied_on(t.knowledge_fragment_id) AS is_unapproved_but_relied_on,-- TRUE when a live procedure is acting on a claim that has not been approved by the knowledge authority.
  calc_knowledge_fragments_evidence_age_days(t.knowledge_fragment_id) AS evidence_age_days,-- Age in days of the elicitation session this claim came from.
  calc_knowledge_fragments_has_recorded_elicitation(t.knowledge_fragment_id) AS has_recorded_elicitation,-- TRUE when this claim traces to a recorded elicitation session.
  calc_knowledge_fragments_is_from_single_witness(t.knowledge_fragment_id) AS is_from_single_witness,-- Whether this claim rests on a single practitioner's account.
  calc_knowledge_fragments_evidence_expiry_days(t.knowledge_fragment_id) AS evidence_expiry_days,-- How many days this claim's evidence is trusted for, given how it was gathered.
  calc_knowledge_fragments_evidence_has_expired(t.knowledge_fragment_id) AS evidence_has_expired,-- TRUE when the evidence behind this claim is older than we trust evidence of its kind to be.
  calc_knowledge_fragments_owner_agent(t.knowledge_fragment_id) AS owner_agent, -- The agent currently holding the role that owns this claim.
  calc_knowledge_fragments_is_awaiting_approval(t.knowledge_fragment_id) AS is_awaiting_approval,-- TRUE when this claim has been reviewed but not yet approved.
  calc_knowledge_fragments_owner_is_me(t.knowledge_fragment_id) AS owner_is_me, -- TRUE when the People Policy Owner role owns this claim.
  calc_knowledge_fragments_is_my_unfinished_approval(t.knowledge_fragment_id) AS is_my_unfinished_approval,-- TRUE when a claim I own has been reviewed and is waiting on my approval.
  calc_knowledge_fragments_is_invoked_by_an_exception(t.knowledge_fragment_id) AS is_invoked_by_an_exception,-- How many documented exception handlers trigger on the same step this claim is attached to.
  calc_knowledge_fragments_has_operational_reliance(t.knowledge_fragment_id) AS has_operational_reliance,-- TRUE when an exception handler exists on the step this claim governs.
  calc_knowledge_fragments_is_unapproved_and_operationally_live(t.knowledge_fragment_id) AS is_unapproved_and_operationally_live,-- TRUE when a claim awaiting my approval is already being acted on through a documented exception path.
  calc_knowledge_fragments_age_days(t.knowledge_fragment_id) AS age_days,       -- Days since this claim became valid.
  calc_knowledge_fragments_is_low_confidence(t.knowledge_fragment_id) AS is_low_confidence,-- TRUE when this claim was recorded with less than high confidence.
  calc_knowledge_fragments_owning_version_cadence_days(t.knowledge_fragment_id) AS owning_version_cadence_days,-- The review cadence promised for the version this claim supports.
  calc_knowledge_fragments_exceeds_owning_cadence(t.knowledge_fragment_id) AS exceeds_owning_cadence,-- TRUE when this claim is older than the review cadence promised for the version it supports.
  calc_knowledge_fragments_is_aging_low_confidence_claim(t.knowledge_fragment_id) AS is_aging_low_confidence_claim,-- TRUE when a claim we were never sure about has also outlived its version's review cadence.
  calc_knowledge_fragments_owner_role_agent_kind(t.knowledge_fragment_id) AS owner_role_agent_kind,-- Agent kind of whoever currently holds the role that owns this knowledge fragment.
  calc_knowledge_fragments_is_human_owned(t.knowledge_fragment_id) AS is_human_owned,-- TRUE when the owning role is currently held by a human.
  calc_knowledge_fragments_is_ai_validated_by_ai(t.knowledge_fragment_id) AS is_ai_validated_by_ai,-- TRUE when knowledge came from a non-human source AND is owned by a non-human-held role.
  calc_knowledge_fragments_review_cadence_days(t.knowledge_fragment_id) AS review_cadence_days,-- The review cadence promised for the procedure version this fragment supports, resolved via ProcedureVersions because INDEX/MATCH only matches a target primary key.
  calc_knowledge_fragments_is_overdue_for_review(t.knowledge_fragment_id) AS is_overdue_for_review,-- TRUE when a currently-valid fragment has gone longer than its stewardship cadence without review.
  calc_knowledge_fragments_predates_current_role_holder(t.knowledge_fragment_id) AS predates_current_role_holder,-- TRUE when this knowledge became valid before the current holder of its owning role took the role.
  calc_knowledge_fragments_owner_role_assignment_valid_from(t.knowledge_fragment_id) AS owner_role_assignment_valid_from,-- When the current holder of the owning role took that role.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM knowledge_fragments t;

-- ----------------------------------------------------------------------------
-- vw_knowledge_gaps: Known unknowns and missing procedural coverage. Explicit ERB-PKO extension used to govern scope and prevent silent incompleteness.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_knowledge_gaps CASCADE;
CREATE VIEW vw_knowledge_gaps WITH (security_invoker = ON) AS
SELECT
  t.knowledge_gap_id,                                                           -- Stored logical identifier for one KnowledgeGaps row.
  calc_knowledge_gaps_name(t.knowledge_gap_id) AS name,                         -- Human-readable calculated display alias for the KnowledgeGaps row.
  t.procedure_version,                                                          -- Affected procedure version.
  t.step,                                                                       -- Affected step.
  t.statement,                                                                  -- What is not yet known or represented.
  t.severity,                                                                   -- Low, Medium, High, or Critical.
  t.blocking_kind,                                                              -- Blocking or NonBlocking.
  t.status,                                                                     -- Open, Investigating, Resolved, AcceptedRisk, or Closed.
  t.owner_role,                                                                 -- Role responsible for resolving the gap.
  t.identified_at,                                                              -- Time the gap was identified.
  t.resolution_plan,                                                            -- Resolution plan or final resolution.
  calc_knowledge_gaps_is_open(t.knowledge_gap_id) AS is_open,                   -- TRUE when the gap remains open.
  calc_knowledge_gaps_open_gap_version_key(t.knowledge_gap_id) AS open_gap_version_key,-- Echoes the ProcedureVersion id for open high-severity knowledge gaps.
  calc_knowledge_gaps_is_blocking(t.knowledge_gap_id) AS is_blocking,           -- TRUE when this gap is declared blocking rather than informational.
  calc_knowledge_gaps_is_open_and_blocking(t.knowledge_gap_id) AS is_open_and_blocking,-- TRUE when this gap is both unresolved and declared blocking.
  calc_knowledge_gaps_days_open(t.knowledge_gap_id) AS days_open,               -- Days this gap has been unresolved, or zero once closed.
  calc_knowledge_gaps_tolerance_days(t.knowledge_gap_id) AS tolerance_days,     -- How long a gap of this severity may remain open before it becomes a governance failure in its own right.
  calc_knowledge_gaps_is_overdue_gap(t.knowledge_gap_id) AS is_overdue_gap,     -- TRUE when this acknowledged unknown has outlived the tolerance for its severity.
  calc_knowledge_gaps_owner_agent(t.knowledge_gap_id) AS owner_agent,           -- The agent currently holding the role that owns resolving this gap.
  calc_knowledge_gaps_owner_is_still_engaged(t.knowledge_gap_id) AS owner_is_still_engaged,-- Whether the agent responsible for closing this gap still holds a role here.
  calc_knowledge_gaps_has_resolution_plan(t.knowledge_gap_id) AS has_resolution_plan,-- TRUE when someone has written down how this gap would be closed.
  calc_knowledge_gaps_is_abandoned_unknown(t.knowledge_gap_id) AS is_abandoned_unknown,-- TRUE when an overdue gap has either no plan or no living owner — an admission of ignorance that nobody is acting on.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM knowledge_gaps t;

-- ----------------------------------------------------------------------------
-- vw_faqs: Frequently asked procedural questions. Maps to pko:FrequentlyAskedQuestion, question, answer, hasFAQCategory, and hasFAQTarget.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_faqs CASCADE;
CREATE VIEW vw_faqs WITH (security_invoker = ON) AS
SELECT
  t.faq_id,                                                                     -- Stored logical identifier for one FAQs row.
  calc_faqs_name(t.faq_id) AS name,                                             -- Human-readable calculated display alias for the FAQs row.
  t.procedure_version,                                                          -- Procedure version addressed by the FAQ.
  t.step,                                                                       -- Optional step targeted by the FAQ.
  t.category,                                                                   -- FAQ category.
  t.target_kind,                                                                -- Procedure, Step, Tool, Resource, or Execution.
  t.question,                                                                   -- FAQ question; maps to pko:question.
  t.answer,                                                                     -- Approved answer; maps to pko:answer.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM faqs t;

-- ----------------------------------------------------------------------------
-- vw_explanations: Explainable derivation artifacts associated with procedural decisions. Maps to pko:Explanation and pko:hasExplanation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_explanations CASCADE;
CREATE VIEW vw_explanations WITH (security_invoker = ON) AS
SELECT
  t.explanation_id,                                                             -- Stored logical identifier for one Explanations row.
  calc_explanations_name(t.explanation_id) AS name,                             -- Human-readable calculated display alias for the Explanations row.
  t.procedure_version,                                                          -- Procedure version explained.
  t.step,                                                                       -- Step explained.
  t.title,                                                                      -- Explanation title.
  t.description,                                                                -- What the explanation traces.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM explanations t;

-- ----------------------------------------------------------------------------
-- vw_procedure_executions: Concrete enactments of procedure specifications. Maps to pko:ProcedureExecution and remains separate from ProcedureVersions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_executions CASCADE;
CREATE VIEW vw_procedure_executions WITH (security_invoker = ON) AS
SELECT
  t.procedure_execution_id,                                                     -- Stored logical identifier for one ProcedureExecutions row.
  calc_procedure_executions_name(t.procedure_execution_id) AS name,             -- Human-readable calculated display alias for the ProcedureExecutions row.
  t.procedure_version,                                                          -- Exact procedure specification executed; maps to pko:hasExecutedProcedure.
  t.execution_status,                                                           -- PKO execution status: InProgress, Completed, Paused, or Cancelled.
  t.started_at,                                                                 -- Execution start; maps to prov:startedAtTime.
  t.ended_at,                                                                   -- Execution end; maps to prov:endedAtTime.
  t.executed_by_agent,                                                          -- Agent accountable for the overall execution; maps to pko:wasExecutedBy.
  t.context,                                                                    -- Execution-specific scope or target.
  t.operational_record_uri,                                                     -- Identifier in the operational execution system.
  calc_procedure_executions_expected_step_count(t.procedure_execution_id) AS expected_step_count,-- How many steps this execution was supposed to perform.
  calc_procedure_executions_completed_step_count(t.procedure_execution_id) AS completed_step_count,-- How many steps of this execution actually reached Completed.
  calc_procedure_executions_control_breach_count(t.procedure_execution_id) AS control_breach_count,-- Total step executions in this run that carry at least one control breach.
  calc_procedure_executions_late_step_count(t.procedure_execution_id) AS late_step_count,-- How many steps in this execution ran long.
  calc_procedure_executions_is_structurally_complete(t.procedure_execution_id) AS is_structurally_complete,-- TRUE when every specified step of the procedure version reached Completed in this execution.
  calc_procedure_executions_diverged_from_specification(t.procedure_execution_id) AS diverged_from_specification,-- TRUE when the execution either skipped specified steps or carried at least one control breach.
  calc_procedure_executions_all_blocking_controls_evaluated(t.procedure_execution_id) AS all_blocking_controls_evaluated,-- TRUE when every blocking requirement bound to every step of this execution received a satisfaction record.
  calc_procedure_executions_unevaluated_blocking_total(t.procedure_execution_id) AS unevaluated_blocking_total,-- How many step executions in this run left at least one blocking control unevaluated.
  calc_procedure_executions_separation_of_duties_held(t.procedure_execution_id) AS separation_of_duties_held,-- TRUE when no agent both prepared and approved within this execution.
  calc_procedure_executions_separation_violation_count(t.procedure_execution_id) AS separation_violation_count,-- Number of segregation-of-duties violations in this execution.
  calc_procedure_executions_is_attestation_ready(t.procedure_execution_id) AS is_attestation_ready,-- TRUE only when every step completed, no control breached, every blocking control was actually evaluated, and segregation of duties held.
  calc_procedure_executions_attestation_blocker_summary(t.procedure_execution_id) AS attestation_blocker_summary,-- Names the highest-severity reason the attestation cannot be signed, or empty when it can.
  calc_procedure_executions_executed_version_is_fit(t.procedure_execution_id) AS executed_version_is_fit,-- Whether the procedure version this execution ran against is currently fit to execute.
  calc_procedure_executions_signed_against_unfit_version(t.procedure_execution_id) AS signed_against_unfit_version,-- TRUE when a completed execution was run against a procedure version the organization no longer stands behind.
  calc_procedure_executions_asserted_only_control_count(t.procedure_execution_id) AS asserted_only_control_count,-- How many blocking controls in this execution passed on human assertion alone.
  calc_procedure_executions_assurance_is_mostly_asserted(t.procedure_execution_id) AS assurance_is_mostly_asserted,-- TRUE when any blocking control in this execution passed without a computed witness behind it.
  calc_procedure_executions_unreachable_handling_failure_count(t.procedure_execution_id) AS unreachable_handling_failure_count,-- Number of deliveries in this execution where unreachable handling was wrong -- either fabricated acknowledgement or no exception invoked.
  calc_procedure_executions_retention_breach_count(t.procedure_execution_id) AS retention_breach_count,-- Number of transmitted messages in this execution whose text we no longer hold despite an active retention obligation.
  calc_procedure_executions_cleared_legal_review_count(t.procedure_execution_id) AS cleared_legal_review_count,-- How many passed legal reviews exist for this execution.
  calc_procedure_executions_has_cleared_legal_review(t.procedure_execution_id) AS has_cleared_legal_review,-- TRUE when legal review has passed for this execution.
  calc_procedure_executions_abandoned_failure_count(t.procedure_execution_id) AS abandoned_failure_count,-- Number of failed deliveries in this run that nobody picked up.
  calc_procedure_executions_delivered_count(t.procedure_execution_id) AS delivered_count,-- Number of confirmed-delivered messages in this run.
  calc_procedure_executions_total_delivery_attempt_count(t.procedure_execution_id) AS total_delivery_attempt_count,-- Total delivery records of any status for this run.
  calc_procedure_executions_has_abandoned_failures(t.procedure_execution_id) AS has_abandoned_failures,-- TRUE when this run has any untriaged delivery failure.
  calc_procedure_executions_mishandled_refusal_count(t.procedure_execution_id) AS mishandled_refusal_count,-- Number of gate refusals in this run that were either overridden or silently dropped.
  calc_procedure_executions_unclean_step_count(t.procedure_execution_id) AS unclean_step_count,-- Number of step executions in this run that were not clean.
  calc_procedure_executions_ran_clean(t.procedure_execution_id) AS ran_clean,   -- TRUE when every step execution in this run was clean.
  calc_procedure_executions_count_of_approval_executions(t.procedure_execution_id) AS count_of_approval_executions,-- How many human approval gates were executed in this run.
  calc_procedure_executions_has_human_approval(t.procedure_execution_id) AS has_human_approval,-- TRUE when at least one human approval gate was executed in this run.
  calc_procedure_executions_count_of_delivery_executions(t.procedure_execution_id) AS count_of_delivery_executions,-- How many times the send step ran in this execution.
  calc_procedure_executions_has_delivered(t.procedure_execution_id) AS has_delivered,-- TRUE when this run has sent communications to employees.
  calc_procedure_executions_delivered_without_approval(t.procedure_execution_id) AS delivered_without_approval,-- TRUE when a run sent employee communications without executing a human approval gate.
  calc_procedure_executions_invalid_approval_count(t.procedure_execution_id) AS invalid_approval_count,-- Number of approval-type requirements in this run that are incomplete or non-human-evaluated.
  calc_procedure_executions_approval_chain_is_complete(t.procedure_execution_id) AS approval_chain_is_complete,-- TRUE when every approval-type requirement in this run is fully satisfied by a human.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedure_executions t;

-- ----------------------------------------------------------------------------
-- vw_step_executions: Concrete executions of specified steps. Maps to pko:StepExecution, hasExecutedStep, includesStepExecution, and nextStepExecution.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_executions CASCADE;
CREATE VIEW vw_step_executions WITH (security_invoker = ON) AS
SELECT
  t.step_execution_id,                                                          -- Stored logical identifier for one StepExecutions row.
  calc_step_executions_name(t.step_execution_id) AS name,                       -- Human-readable calculated display alias for the StepExecutions row.
  t.procedure_execution,                                                        -- Parent procedure execution.
  t.step,                                                                       -- Specified step executed; maps to pko:hasExecutedStep.
  t.executed_by_agent,                                                          -- Agent executing the step; maps to pko:wasExecutedBy.
  t.execution_status,                                                           -- InProgress, Completed, Paused, Cancelled, or Failed.
  t.started_at,                                                                 -- Execution start.
  t.ended_at,                                                                   -- Execution end.
  t.verification_result,                                                        -- PASS, WARN, FAIL, or PENDING.
  t.deviation,                                                                  -- Observed deviation from the specification.
  calc_step_executions_actual_duration_minutes(t.step_execution_id) AS actual_duration_minutes,-- Observed duration in minutes.
  calc_step_executions_expected_duration_minutes(t.step_execution_id) AS expected_duration_minutes,-- Expected duration from the specification.
  calc_step_executions_is_late(t.step_execution_id) AS is_late,                 -- TRUE when actual duration exceeds expected duration.
  calc_step_executions_blocking_unmet_count(t.step_execution_id) AS blocking_unmet_count,-- How many blocking requirements attached to this step execution are recorded as not fully satisfied.
  calc_step_executions_blocking_unmet_count_safe(t.step_execution_id) AS blocking_unmet_count_safe,-- Count of blocking-but-unmet requirements on this step execution, computed via the single-criterion key so no criterion is dropped.
  calc_step_executions_proceeded_past_blocking_control(t.step_execution_id) AS proceeded_past_blocking_control,-- TRUE when a step execution reached Completed even though a blocking requirement on it was never fully satisfied.
  calc_step_executions_expected_blocking_count(t.step_execution_id) AS expected_blocking_count,-- How many blocking requirements this execution's step was supposed to have evaluated.
  calc_step_executions_evaluated_blocking_count(t.step_execution_id) AS evaluated_blocking_count,-- How many blocking requirements actually received a satisfaction record on this step execution, at any level.
  calc_step_executions_unevaluated_blocking_count(t.step_execution_id) AS unevaluated_blocking_count,-- Blocking requirements that were bound to this step but never assessed on this execution.
  calc_step_executions_has_unevaluated_blocking_control(t.step_execution_id) AS has_unevaluated_blocking_control,-- TRUE when at least one blocking control bound to this step was never evaluated on this execution.
  calc_step_executions_stale_authoritative_source_count(t.step_execution_id) AS stale_authoritative_source_count,-- Number of stale authoritative sources bound to the step this execution ran.
  calc_step_executions_ran_on_stale_authoritative_source(t.step_execution_id) AS ran_on_stale_authoritative_source,-- TRUE when this execution's step depends on at least one authoritative source that is outside its freshness SLA.
  calc_step_executions_has_deviation_note(t.step_execution_id) AS has_deviation_note,-- TRUE when a human recorded some deviation narrative on this execution.
  calc_step_executions_is_late_and_unexplained(t.step_execution_id) AS is_late_and_unexplained,-- TRUE when the execution exceeded its expected duration and no deviation was recorded.
  calc_step_executions_available_exception_count_for_step(t.step_execution_id) AS available_exception_count_for_step,-- How many active exceptions were available to this execution's step.
  calc_step_executions_had_uninvoked_exception_available(t.step_execution_id) AS had_uninvoked_exception_available,-- TRUE when an execution ran long with no explanation despite the specification defining an active exception for exactly that situation.
  calc_step_executions_expected_verification_count(t.step_execution_id) AS expected_verification_count,-- How many verifications this execution was supposed to perform.
  calc_step_executions_performed_verification_count(t.step_execution_id) AS performed_verification_count,-- How many verification outcomes were actually recorded against this execution.
  calc_step_executions_skipped_verification_count(t.step_execution_id) AS skipped_verification_count,-- Declared verifications with no recorded outcome on this execution.
  calc_step_executions_has_skipped_verification(t.step_execution_id) AS has_skipped_verification,-- TRUE when a declared verification was never performed on this execution.
  calc_step_executions_claims_pass_without_evidence(t.step_execution_id) AS claims_pass_without_evidence,-- TRUE when an execution asserts PASS while at least one declared verification has no recorded outcome.
  calc_step_executions_step_is_preparation(t.step_execution_id) AS step_is_preparation,-- Whether this execution ran a preparation step.
  calc_step_executions_step_is_approval(t.step_execution_id) AS step_is_approval,-- Whether this execution ran an approval step.
  calc_step_executions_preparer_agent_key(t.step_execution_id) AS preparer_agent_key,-- Composite execution+agent key, emitted only for preparation steps.
  calc_step_executions_approver_agent_key(t.step_execution_id) AS approver_agent_key,-- Composite execution+agent key, emitted only for approval steps.
  calc_step_executions_prepared_by_this_agent_count(t.step_execution_id) AS prepared_by_this_agent_count,-- On an approval row, how many preparation steps in the SAME procedure execution were run by this same agent.
  calc_step_executions_violates_separation_of_duties(t.step_execution_id) AS violates_separation_of_duties,-- TRUE when the agent approving this step also prepared work earlier in the same procedure execution.
  calc_step_executions_required_role_for_step(t.step_execution_id) AS required_role_for_step,-- The role the specification assigns to this step.
  calc_step_executions_executor_role_key(t.step_execution_id) AS executor_role_key,-- The agent+role pair that would need to exist as a valid assignment for this execution to be properly authorized.
  calc_step_executions_executor_authority_count(t.step_execution_id) AS executor_authority_count,-- How many currently-valid role assignments grant this executor the role their step required.
  calc_step_executions_executor_held_required_role(t.step_execution_id) AS executor_held_required_role,-- TRUE when the executing agent holds a currently-valid assignment to the role the step required.
  calc_step_executions_is_unauthorized_approval(t.step_execution_id) AS is_unauthorized_approval,-- TRUE when an approval step was executed by an agent who does not hold the required approving role.
  calc_step_executions_completed_execution_key(t.step_execution_id) AS completed_execution_key,-- Echoes the parent execution id only for completed steps.
  calc_step_executions_control_breach_execution_key(t.step_execution_id) AS control_breach_execution_key,-- Echoes the parent execution id when this step execution carries ANY control breach.
  calc_step_executions_late_execution_key(t.step_execution_id) AS late_execution_key,-- Echoes the parent execution id only for steps that ran past their expected duration.
  calc_step_executions_executor_agent_kind(t.step_execution_id) AS executor_agent_kind,-- Human, AIAgent, or AutomatedPipeline — what kind of agent actually ran this step.
  calc_step_executions_executor_is_human(t.step_execution_id) AS executor_is_human,-- TRUE when a human executed this step.
  calc_step_executions_step_requires_human_confirmation(t.step_execution_id) AS step_requires_human_confirmation,-- Whether the specification requires this step to be human-confirmed.
  calc_step_executions_non_human_ran_human_step(t.step_execution_id) AS non_human_ran_human_step,-- TRUE when a step requiring human confirmation was executed by an AI agent or automated pipeline.
  calc_step_executions_non_human_approval(t.step_execution_id) AS non_human_approval,-- TRUE when an approval-authority step was executed by a non-human agent, regardless of the RequiresHumanConfirmation flag.
  calc_step_executions_unevaluated_blocking_execution_key(t.step_execution_id) AS unevaluated_blocking_execution_key,-- Echoes the parent execution id when this step left a blocking control unevaluated.
  calc_step_executions_separation_violation_execution_key(t.step_execution_id) AS separation_violation_execution_key,-- Echoes the parent execution id when this step execution violates segregation of duties.
  calc_step_executions_self_witnessed_verification_count(t.step_execution_id) AS self_witnessed_verification_count,-- How many of this execution's verifications were observed by the same agent who ran the step.
  calc_step_executions_unbacked_verification_count(t.step_execution_id) AS unbacked_verification_count,-- How many verifications on this execution recorded a matching signal with no retained evidence artifact.
  calc_step_executions_approval_rests_on_self_attestation(t.step_execution_id) AS approval_rests_on_self_attestation,-- TRUE when an approval step's verification was either self-witnessed by the approver or never performed at all.
  calc_step_executions_exception_invocation_count(t.step_execution_id) AS exception_invocation_count,-- How many specified exceptions were invoked during this step execution.
  calc_step_executions_ran_under_exception(t.step_execution_id) AS ran_under_exception,-- TRUE when this execution invoked at least one specified exception.
  calc_step_executions_is_completed(t.step_execution_id) AS is_completed,       -- TRUE when this step execution reached a completed state.
  calc_step_executions_is_verification_passed(t.step_execution_id) AS is_verification_passed,-- TRUE only when this step execution's verification actually passed. PENDING and FAIL are both not-passed.
  calc_step_executions_is_legal_review_step(t.step_execution_id) AS is_legal_review_step,-- TRUE for executions of the legal and privacy review step.
  calc_step_executions_cleared_legal_review_key(t.step_execution_id) AS cleared_legal_review_key,-- Carries the execution id only when this row is a PASSED legal review; empty string otherwise.
  calc_step_executions_assigned_role(t.step_execution_id) AS assigned_role,     -- The role the specification assigns to this step.
  calc_step_executions_role_current_agent(t.step_execution_id) AS role_current_agent,-- The agent currently designated to hold the step's assigned role.
  calc_step_executions_executor_is_designated_agent(t.step_execution_id) AS executor_is_designated_agent,-- TRUE when the agent that executed the step is the agent currently designated for the step's role.
  calc_step_executions_inputs_were_fresh_at_run(t.step_execution_id) AS inputs_were_fresh_at_run,-- Freshness verdict for the step this execution ran.
  calc_step_executions_ran_on_stale_inputs(t.step_execution_id) AS ran_on_stale_inputs,-- TRUE when an execution completed even though its step's authoritative inputs are stale.
  calc_step_executions_unresolved_issue_count(t.step_execution_id) AS unresolved_issue_count,-- Number of unresolved issue occurrences recorded against this execution.
  calc_step_executions_has_deviation(t.step_execution_id) AS has_deviation,     -- TRUE when a deviation from the specification was recorded.
  calc_step_executions_is_clean(t.step_execution_id) AS is_clean,               -- TRUE when this execution passed verification, deviated from nothing, left no open issue, and finished on time.
  calc_step_executions_procedure_execution_when_unclean(t.step_execution_id) AS procedure_execution_when_unclean,-- Echoes the parent execution id when this step execution is not clean, blank otherwise.
  calc_step_executions_evaluated_requirement_count(t.step_execution_id) AS evaluated_requirement_count,-- Number of requirements actually scored against this execution.
  calc_step_executions_required_blocking_count(t.step_execution_id) AS required_blocking_count,-- Number of blocking requirements the specification demands for this step.
  calc_step_executions_has_unevaluated_blocking_requirement(t.step_execution_id) AS has_unevaluated_blocking_requirement,-- TRUE when fewer requirements were scored than the step has blocking requirements.
  calc_step_executions_executing_agent_kind(t.step_execution_id) AS executing_agent_kind,-- The kind of agent that actually performed this step execution.
  calc_step_executions_was_executed_by_software(t.step_execution_id) AS was_executed_by_software,-- TRUE when software actually performed this step.
  calc_step_executions_step_is_software_assigned(t.step_execution_id) AS step_is_software_assigned,-- Whether the step being executed was specified as a software step.
  calc_step_executions_software_did_human_work(t.step_execution_id) AS software_did_human_work,-- TRUE when software performed a step the procedure specified for a human.
  calc_step_executions_is_approval_execution(t.step_execution_id) AS is_approval_execution,-- Whether this execution is of a designated human approval gate.
  calc_step_executions_is_verified(t.step_execution_id) AS is_verified,         -- TRUE when this execution recorded a positive verification outcome.
  calc_step_executions_unconfirmed_non_human_decision_count(t.step_execution_id) AS unconfirmed_non_human_decision_count,-- Number of material non-human decisions in this execution that no human confirmed.
  calc_step_executions_requires_human_confirmation(t.step_execution_id) AS requires_human_confirmation,-- Whether the specification requires human confirmation for this step.
  calc_step_executions_human_confirmation_missing(t.step_execution_id) AS human_confirmation_missing,-- TRUE when a step requiring human confirmation contains unconfirmed material non-human decisions.
  calc_step_executions_drafted_from_unusable_source(t.step_execution_id) AS drafted_from_unusable_source,-- TRUE when a drafting execution completed despite an unapproved or stale source at its step.
  calc_step_executions_inputs_were_usable(t.step_execution_id) AS inputs_were_usable,-- Source-usability verdict for the step this execution ran.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM step_executions t;

-- ----------------------------------------------------------------------------
-- vw_requirement_satisfactions: Execution-time evaluations of requirements. Maps to pko:RequirementSatisfaction, refersToRequirement, and hasRequirementSatisfactionLevel.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_requirement_satisfactions CASCADE;
CREATE VIEW vw_requirement_satisfactions WITH (security_invoker = ON) AS
SELECT
  t.requirement_satisfaction_id,                                                -- Stored logical identifier for one RequirementSatisfactions row.
  calc_requirement_satisfactions_name(t.requirement_satisfaction_id) AS name,   -- Human-readable calculated display alias for the RequirementSatisfactions row.
  t.step_execution,                                                             -- Execution being evaluated.
  t.requirement,                                                                -- Requirement evaluated.
  t.satisfaction_level,                                                         -- NotEvaluated, NotSatisfied, PartiallySatisfied, or Satisfied.
  t.evidence,                                                                   -- Evidence supporting the evaluation.
  t.evaluated_by_agent,                                                         -- Agent that evaluated satisfaction.
  t.evaluated_at,                                                               -- Evaluation timestamp.
  calc_requirement_satisfactions_requirement_is_blocking(t.requirement_satisfaction_id) AS requirement_is_blocking,-- Whether the requirement being evaluated on this satisfaction row is a blocking control.
  calc_requirement_satisfactions_is_fully_satisfied(t.requirement_satisfaction_id) AS is_fully_satisfied,-- TRUE only when the requirement is recorded as fully Satisfied. PartiallySatisfied, Unsatisfied, Waived, and blank are all FALSE.
  calc_requirement_satisfactions_is_blocking_and_unmet(t.requirement_satisfaction_id) AS is_blocking_and_unmet,-- TRUE when a blocking requirement is recorded at anything less than fully Satisfied. This is the control-failure witness at the requirement grain.
  calc_requirement_satisfactions_blocking_unmet_step_key(t.requirement_satisfaction_id) AS blocking_unmet_step_key,-- Echoes the parent StepExecution id only when this row is a blocking-unmet violation; empty string otherwise.
  calc_requirement_satisfactions_blocking_satisfaction_step_key(t.requirement_satisfaction_id) AS blocking_satisfaction_step_key,-- Echoes the parent StepExecution id when this satisfaction row concerns a blocking requirement.
  calc_requirement_satisfactions_negative_outcome_requirement_key(t.requirement_satisfaction_id) AS negative_outcome_requirement_key,-- Echoes the Requirement id only when this evaluation came out at less than fully Satisfied.
  calc_requirement_satisfactions_evaluator_agent_kind(t.requirement_satisfaction_id) AS evaluator_agent_kind,-- What kind of agent evaluated this requirement satisfaction.
  calc_requirement_satisfactions_non_human_evaluated_human_contro(t.requirement_satisfaction_id) AS non_human_evaluated_human_control,-- TRUE when a blocking requirement was evaluated by a non-human agent.
  calc_requirement_satisfactions_requirement_has_computed_witness(t.requirement_satisfaction_id) AS requirement_has_computed_witness,-- Whether the requirement this row evaluates has a computed witness behind it.
  calc_requirement_satisfactions_is_asserted_only(t.requirement_satisfaction_id) AS is_asserted_only,-- TRUE when a blocking requirement is recorded as Satisfied purely on human assertion, with no computed predicate behind it.
  calc_requirement_satisfactions_asserted_only_execution_key(t.requirement_satisfaction_id) AS asserted_only_execution_key,-- Echoes the grandparent procedure execution id for assertion-only satisfactions.
  calc_requirement_satisfactions_parent_procedure_execution(t.requirement_satisfaction_id) AS parent_procedure_execution,-- The procedure execution this satisfaction ultimately belongs to.
  calc_requirement_satisfactions_step_execution_when_scored(t.requirement_satisfaction_id) AS step_execution_when_scored,-- Echoes the step-execution id when a satisfaction level was actually recorded, blank otherwise.
  calc_requirement_satisfactions_is_human_evaluated(t.requirement_satisfaction_id) AS is_human_evaluated,-- TRUE when a human evaluated this requirement satisfaction.
  calc_requirement_satisfactions_requirement_is_approval_type(t.requirement_satisfaction_id) AS requirement_is_approval_type,-- The requirement's type, e.g. Approval, Control, Privacy.
  calc_requirement_satisfactions_is_invalid_approval(t.requirement_satisfaction_id) AS is_invalid_approval,-- TRUE when an approval-type requirement is not fully satisfied, or was not evaluated by a human.
  calc_requirement_satisfactions_procedure_execution_of_satisfact(t.requirement_satisfaction_id) AS procedure_execution_of_satisfaction,-- The run this satisfaction belongs to.
  calc_requirement_satisfactions_run_when_invalid_approval(t.requirement_satisfaction_id) AS run_when_invalid_approval,-- Echoes the run id when this is an invalid approval, blank otherwise.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM requirement_satisfactions t;

-- ----------------------------------------------------------------------------
-- vw_errors: Reusable error definitions encountered during execution. Maps to pko:Error, errorCode, and errorCause.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_errors CASCADE;
CREATE VIEW vw_errors WITH (security_invoker = ON) AS
SELECT
  t.error_id,                                                                   -- Stored logical identifier for one Errors row.
  calc_errors_name(t.error_id) AS name,                                         -- Human-readable calculated display alias for the Errors row.
  t.label,                                                                      -- Error label.
  t.error_code,                                                                 -- Error code; maps to pko:errorCode.
  t.error_cause,                                                                -- Known or suspected cause; maps to pko:errorCause.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM errors t;

-- ----------------------------------------------------------------------------
-- vw_issue_occurrences: Concrete issue events during execution. Maps to pko:IssueOccurrence, hasEncounteredError, wasEncounteredBy, issueCause, and issueSolution.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_issue_occurrences CASCADE;
CREATE VIEW vw_issue_occurrences WITH (security_invoker = ON) AS
SELECT
  t.issue_occurrence_id,                                                        -- Stored logical identifier for one IssueOccurrences row.
  calc_issue_occurrences_name(t.issue_occurrence_id) AS name,                   -- Human-readable calculated display alias for the IssueOccurrences row.
  t.step_execution,                                                             -- Step execution during which the issue occurred.
  t.error,                                                                      -- Error encountered.
  t.encountered_by_agent,                                                       -- Agent that encountered or reported the issue.
  t.occurred_at,                                                                -- Occurrence time.
  t.issue_cause,                                                                -- Execution-specific cause; maps to pko:issueCause.
  t.issue_solution,                                                             -- Applied solution; maps to pko:issueSolution.
  t.status,                                                                     -- Open, Monitoring, Resolved, or Closed.
  calc_issue_occurrences_is_unresolved(t.issue_occurrence_id) AS is_unresolved, -- TRUE when this issue occurrence has not been closed out.
  calc_issue_occurrences_step_execution_when_unresolved(t.issue_occurrence_id) AS step_execution_when_unresolved,-- Echoes the step-execution id when the issue is unresolved, blank otherwise.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM issue_occurrences t;

-- ----------------------------------------------------------------------------
-- vw_user_questions: Questions asked by agents during execution. Maps to pko:UserQuestionOccurrence, questionByUser, wasAskedBy, and isQuestionAddressedBy.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_user_questions CASCADE;
CREATE VIEW vw_user_questions WITH (security_invoker = ON) AS
SELECT
  t.user_question_id,                                                           -- Stored logical identifier for one UserQuestions row.
  calc_user_questions_name(t.user_question_id) AS name,                         -- Human-readable calculated display alias for the UserQuestions row.
  t.step_execution,                                                             -- Execution context for the question.
  t.asked_by_agent,                                                             -- Agent asking the question.
  t.asked_at,                                                                   -- Question time.
  t.question_text,                                                              -- Question text; maps to pko:questionByUser.
  t.resolved_by_faq,                                                            -- FAQ used to resolve the question.
  t.addressed_by_resource,                                                      -- Resource that addressed the question.
  t.status,                                                                     -- Open, Answered, Escalated, or Closed.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM user_questions t;

-- ----------------------------------------------------------------------------
-- vw_user_feedback: Feedback supplied by users about a procedure or execution. Maps to pko:UserFeedbackOccurrence, feedbackOnProcedureExecution, and wasProvidedBy.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_user_feedback CASCADE;
CREATE VIEW vw_user_feedback WITH (security_invoker = ON) AS
SELECT
  t.user_feedback_id,                                                           -- Stored logical identifier for one UserFeedback row.
  calc_user_feedback_name(t.user_feedback_id) AS name,                          -- Human-readable calculated display alias for the UserFeedback row.
  t.procedure_execution,                                                        -- Execution receiving feedback.
  t.provided_by_agent,                                                          -- Agent providing feedback.
  t.provided_at,                                                                -- Feedback time.
  t.feedback_text,                                                              -- Feedback statement.
  t.disposition,                                                                -- Accepted, Rejected, UnderReview, or Deferred.
  t.change_request_key,                                                         -- Related change request identifier.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM user_feedback t;

-- ----------------------------------------------------------------------------
-- vw_stewardship_assignments: Separates ongoing stewardship from authority to approve semantic commitments. Explicit ERB-PKO governance extension.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_stewardship_assignments CASCADE;
CREATE VIEW vw_stewardship_assignments WITH (security_invoker = ON) AS
SELECT
  t.stewardship_assignment_id,                                                  -- Stored logical identifier for one StewardshipAssignments row.
  calc_stewardship_assignments_name(t.stewardship_assignment_id) AS name,       -- Human-readable calculated display alias for the StewardshipAssignments row.
  t.procedure_version,                                                          -- Governed procedure version.
  t.steward_role,                                                               -- Role responsible for health, review, and maintenance.
  t.authority_role,                                                             -- Role authorized to approve semantic changes.
  t.valid_from,                                                                 -- Start of stewardship interval.
  t.valid_to,                                                                   -- End of stewardship interval.
  t.review_cadence_days,                                                        -- Required review cadence.
  calc_stewardship_assignments_count_of_review_events(t.stewardship_assignment_id) AS count_of_review_events,-- How many review events have ever been recorded for the procedure version this assignment stewards.
  calc_stewardship_assignments_has_ever_been_reviewed(t.stewardship_assignment_id) AS has_ever_been_reviewed,-- TRUE if at least one review event exists for the stewarded procedure version.
  calc_stewardship_assignments_is_current_assignment(t.stewardship_assignment_id) AS is_current_assignment,-- TRUE when this stewardship assignment is in force right now.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM stewardship_assignments t;

-- ----------------------------------------------------------------------------
-- vw_change_requests: Governed requests for semantic or operational change, anchored to a procedure version and authority. Explicit ERB-PKO extension.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_change_requests CASCADE;
CREATE VIEW vw_change_requests WITH (security_invoker = ON) AS
SELECT
  t.change_request_id,                                                          -- Stored logical identifier for one ChangeRequests row.
  calc_change_requests_name(t.change_request_id) AS name,                       -- Human-readable calculated display alias for the ChangeRequests row.
  t.procedure_version,                                                          -- Procedure version affected.
  t.title,                                                                      -- Change title.
  t.change_kind,                                                                -- Defect, Enhancement, NewRequirement, DataOperation, or BreakingChange.
  t.status,                                                                     -- Draft, UnderReview, Approved, Rejected, Implemented, or Closed.
  t.requested_by_agent,                                                         -- Agent requesting the change.
  t.authority_role,                                                             -- Role authorized to approve the change.
  t.requested_at,                                                               -- Request time.
  t.decided_at,                                                                 -- Decision time.
  t.impact_assessment,                                                          -- Expected effect on commitments, data, projections, and tests.
  calc_change_requests_is_open(t.change_request_id) AS is_open,                 -- TRUE while the request remains active.
  calc_change_requests_open_change_version_key(t.change_request_id) AS open_change_version_key,-- Echoes the ProcedureVersion id only for change requests still open.
  calc_change_requests_is_decided(t.change_request_id) AS is_decided,           -- TRUE when a decision timestamp has been recorded.
  calc_change_requests_days_pending(t.change_request_id) AS days_pending,       -- Days from request to decision, or to now if still undecided.
  calc_change_requests_is_still_pending(t.change_request_id) AS is_still_pending,-- TRUE when the request is in an open status and has no decision recorded.
  calc_change_requests_is_stalled(t.change_request_id) AS is_stalled,           -- TRUE when an undecided change request has been pending more than fourteen days.
  calc_change_requests_authority_agent(t.change_request_id) AS authority_agent, -- The agent currently holding the authority role that owes a decision on this request.
  calc_change_requests_requester_is_authority(t.change_request_id) AS requester_is_authority,-- TRUE when the agent who raised the request is also the agent who decides it.
  calc_change_requests_awaits_authority_decision(t.change_request_id) AS awaits_authority_decision,-- TRUE when this request is formally before its authority and no decision has been recorded.
  calc_change_requests_authority_role_label(t.change_request_id) AS authority_role_label,-- Human-readable label of the role that owes a decision.
  calc_change_requests_touches_live_version(t.change_request_id) AS touches_live_version,-- Whether the version this request would alter is currently executable.
  calc_change_requests_is_live_decision_backlog(t.change_request_id) AS is_live_decision_backlog,-- TRUE when a decision I owe is blocking a change to a procedure currently in production.
  calc_change_requests_blocks_an_open_gap(t.change_request_id) AS blocks_an_open_gap,-- TRUE when an undecided request against a live version is the kind that exists to close a known gap.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM change_requests t;

-- ----------------------------------------------------------------------------
-- vw_review_events: Periodic governance reviews that test competency coverage, staleness, and semantic integrity. Explicit ERB-PKO extension represented as prov:Activity.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_review_events CASCADE;
CREATE VIEW vw_review_events WITH (security_invoker = ON) AS
SELECT
  t.review_event_id,                                                            -- Stored logical identifier for one ReviewEvents row.
  calc_review_events_name(t.review_event_id) AS name,                           -- Human-readable calculated display alias for the ReviewEvents row.
  t.procedure_version,                                                          -- Reviewed procedure version.
  t.review_kind,                                                                -- Review type.
  t.reviewed_at,                                                                -- Review timestamp.
  t.reviewed_by_agent,                                                          -- Reviewing agent.
  t.outcome,                                                                    -- Passed, PassedWithChange, Failed, or Deferred.
  t.related_change_request,                                                     -- Change request produced or considered.
  t.next_review_due,                                                            -- Next required review.
  t.evaluation_context,                                                         -- The evaluation context this row's time-dependent witnesses are judged under.
  calc_review_events_as_of_instant(t.review_event_id) AS as_of_instant,         -- The evaluation instant this row's time-dependent witnesses are judged against.
  calc_review_events_is_overdue(t.review_event_id) AS is_overdue,               -- TRUE when review is overdue.
  calc_review_events_overdue_version_key(t.review_event_id) AS overdue_version_key,-- Echoes the ProcedureVersion id only when this review is past its next-due date.
  calc_review_events_promised_cadence_days(t.review_event_id) AS promised_cadence_days,-- The review cadence promised for this procedure version, resolved via ProcedureVersions because INDEX/MATCH can only match a target table primary key.
  calc_review_events_days_since_reviewed(t.review_event_id) AS days_since_reviewed,-- Elapsed days since this review actually happened.
  calc_review_events_exceeds_promised_cadence(t.review_event_id) AS exceeds_promised_cadence,-- TRUE when more days have elapsed since this review than the stewardship assignment promised as a cadence.
  calc_review_events_cadence_drift_days(t.review_event_id) AS cadence_drift_days,-- Signed drift: positive means we are past the promised cadence by this many days; negative means we are still inside it.
  calc_review_events_promise_and_behavior_disagree(t.review_event_id) AS promise_and_behavior_disagree,-- TRUE when the promised cadence has been blown but the hand-entered NextReviewDue still says we are fine.
  t.semantic_type_iri                                                           -- Class IRI used in projection.
FROM review_events t;

-- ----------------------------------------------------------------------------
-- vw_learning_activities: Learning, retrospective, tabletop, and onboarding activities that convert execution experience into maintained knowledge. Explicit ERB-PKO extension represented as prov:Activity.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_learning_activities CASCADE;
CREATE VIEW vw_learning_activities WITH (security_invoker = ON) AS
SELECT
  t.learning_activity_id,                                                       -- Stored logical identifier for one LearningActivities row.
  calc_learning_activities_name(t.learning_activity_id) AS name,                -- Human-readable calculated display alias for the LearningActivities row.
  t.community_of_practice,                                                      -- Community hosting the activity.
  t.procedure_version,                                                          -- Procedure version practiced or reviewed.
  t.activity_kind,                                                              -- Retrospective, TabletopExercise, Onboarding, Drill, or Apprenticeship.
  t.occurred_at,                                                                -- Activity time.
  t.facilitator_agent,                                                          -- Facilitator.
  t.outcome,                                                                    -- Knowledge or competence produced.
  t.evidence_resource,                                                          -- Evidence or material produced.
  t.semantic_type_iri                                                           -- Class IRI used in projection.
FROM learning_activities t;

-- ----------------------------------------------------------------------------
-- vw_operational_bindings: Live bindings between procedural semantics and operational data/resources. Explicit ERB-PKO extension using DCAT/DCMI/PROV identifiers.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_operational_bindings CASCADE;
CREATE VIEW vw_operational_bindings WITH (security_invoker = ON) AS
SELECT
  t.operational_binding_id,                                                     -- Stored logical identifier for one OperationalBindings row.
  calc_operational_bindings_name(t.operational_binding_id) AS name,             -- Human-readable calculated display alias for the OperationalBindings row.
  t.procedure_version,                                                          -- Procedure version using the binding.
  t.step,                                                                       -- Step using the binding.
  t.resource,                                                                   -- Bound operational resource.
  t.access_mode,                                                                -- Read, Write, ReadWrite, Subscribe, or Publish.
  t.record_or_schema_key,                                                       -- Operational record, table, event, or schema key.
  t.last_observed_at,                                                           -- Most recent successful observation.
  t.freshness_sla_minutes,                                                      -- Maximum allowed data age.
  t.is_authoritative,                                                           -- TRUE when the binding is authoritative for the represented fact.
  t.evaluation_context,                                                         -- The evaluation context this row's time-dependent witnesses are judged under.
  calc_operational_bindings_as_of_instant(t.operational_binding_id) AS as_of_instant,-- The evaluation instant this row's time-dependent witnesses are judged against.
  calc_operational_bindings_age_minutes(t.operational_binding_id) AS age_minutes,-- Current observed age.
  calc_operational_bindings_is_fresh(t.operational_binding_id) AS is_fresh,     -- TRUE when within freshness SLA.
  calc_operational_bindings_stale_binding_step_key(t.operational_binding_id) AS stale_binding_step_key,-- Echoes the bound Step id only when the binding is outside its freshness SLA.
  calc_operational_bindings_authoritative_stale_step_key(t.operational_binding_id) AS authoritative_stale_step_key,-- Echoes the bound Step id only when an AUTHORITATIVE binding is stale.
  calc_operational_bindings_is_stale_and_authoritative(t.operational_binding_id) AS is_stale_and_authoritative,-- TRUE when an authoritative binding has aged past its freshness SLA.
  calc_operational_bindings_step_when_stale(t.operational_binding_id) AS step_when_stale,-- Echoes the step id when this authoritative binding is stale, blank otherwise.
  calc_operational_bindings_resource_is_approved(t.operational_binding_id) AS resource_is_approved,-- Whether the resource behind this binding is an approved source.
  calc_operational_bindings_is_usable_for_drafting(t.operational_binding_id) AS is_usable_for_drafting,-- TRUE when this binding points at an approved source that is still inside its freshness SLA.
  calc_operational_bindings_step_when_unusable(t.operational_binding_id) AS step_when_unusable,-- Echoes the step id when this binding is NOT usable for drafting, blank otherwise.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM operational_bindings t;

-- ----------------------------------------------------------------------------
-- vw_communication_policies: Channel-specific communication policy projected from the same canonical procedure. Uses ODRL-style policy semantics plus ERB-PKO channel constraints.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_communication_policies CASCADE;
CREATE VIEW vw_communication_policies WITH (security_invoker = ON) AS
SELECT
  t.communication_policy_id,                                                    -- Stored logical identifier for one CommunicationPolicies row.
  calc_communication_policies_name(t.communication_policy_id) AS name,          -- Human-readable calculated display alias for the CommunicationPolicies row.
  t.procedure_version,                                                          -- Procedure version governing the channel.
  t.channel,                                                                    -- Email, SMS, Push, Postal, or another declared channel.
  t.audience_rule,                                                              -- Rule that identifies eligible recipients.
  t.consent_required,                                                           -- Whether active consent is required.
  t.quiet_hours_start,                                                          -- Recipient-local quiet-hours start.
  t.quiet_hours_end,                                                            -- Recipient-local quiet-hours end.
  t.max_message_length,                                                         -- Maximum message length for one unit.
  t.max_segments,                                                               -- Maximum number of channel segments.
  t.retention_days,                                                             -- Retention period for rendered messages and delivery records.
  t.approval_role,                                                              -- Role approving the channel policy.
  t.required_content,                                                           -- Content that every message must include.
  t.authority_statement,                                                        -- Which artifact is authoritative.
  t.status,                                                                     -- Draft, Active, Suspended, or Retired.
  calc_communication_policies_consent_violation_count(t.communication_policy_id) AS consent_violation_count,-- Number of consent violations attributable to this channel policy.
  t.quiet_hours_start_hour,                                                     -- The hour (0-23) at which the quiet window opens. Stored rather than parsed from QuietHoursStart: VALUE(LEFT(...)) does not translate — the transpiler casts the "20:00" string to a timestamp and the view errors. The sending system already knows this number, so modeling it as a parse would dress a broken derivation up as a rule.
  t.quiet_hours_end_hour,                                                       -- Numeric hour 0-23 at which quiet hours end. Seeded 8 for comm-sms-policy, 0 for comm-email-policy.
  calc_communication_policies_quiet_hours_violation_count(t.communication_policy_id) AS quiet_hours_violation_count,-- Number of transmitted messages that breached this policy's quiet-hours window.
  t.required_opt_out_phrase,                                                    -- The exact opt-out phrase every message on this channel must contain. Seeded 'Reply STOP' for comm-sms-policy, empty string for comm-email-policy.
  calc_communication_policies_is_active_policy(t.communication_policy_id) AS is_active_policy,-- TRUE only when this channel policy is in Active status.
  t.semantic_type_iri                                                           -- ODRL Policy class IRI.
FROM communication_policies t;

-- ----------------------------------------------------------------------------
-- vw_message_templates: Approved channel templates projected from the canonical rulebook without becoming a second source of policy meaning.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_message_templates CASCADE;
CREATE VIEW vw_message_templates WITH (security_invoker = ON) AS
SELECT
  t.message_template_id,                                                        -- Stored logical identifier for one MessageTemplates row.
  calc_message_templates_name(t.message_template_id) AS name,                   -- Human-readable calculated display alias for the MessageTemplates row.
  t.communication_policy,                                                       -- Channel policy governing the template.
  t.resource,                                                                   -- Template resource.
  t.subject_template,                                                           -- Subject template where supported.
  t.body_template,                                                              -- Body template.
  t.locale,                                                                     -- Locale or language tag.
  t.status,                                                                     -- Draft, Approved, Retired, or Superseded.
  calc_message_templates_policy_max_message_length(t.message_template_id) AS policy_max_message_length,-- Per-segment character limit inherited from the governing channel policy.
  calc_message_templates_policy_max_segments(t.message_template_id) AS policy_max_segments,-- Maximum permitted segment count from the governing channel policy.
  calc_message_templates_body_template_length(t.message_template_id) AS body_template_length,-- Character length of the raw template body before variable substitution.
  calc_message_templates_is_template_over_length(t.message_template_id) AS is_template_over_length,-- TRUE when the template body alone already exceeds the single-segment limit before any variables are substituted in.
  calc_message_templates_valid_approval_count(t.message_template_id) AS valid_approval_count,-- Number of properly-authorized approvals on record for this template.
  calc_message_templates_has_valid_approval(t.message_template_id) AS has_valid_approval,-- TRUE when at least one properly-authorized approval exists for this template.
  calc_message_templates_is_claiming_unbacked_approval(t.message_template_id) AS is_claiming_unbacked_approval,-- TRUE when a template's Status says Approved but no properly-authorized approval record backs it. The phantom-approval witness.
  t.current_body_hash,                                                          -- Digest of the template's current body text, maintained whenever the body is edited.
  calc_message_templates_last_approved_body_hash(t.message_template_id) AS last_approved_body_hash,-- Digest of the body text as it stood at the most recent valid approval.
  t.last_valid_approval,                                                        -- The TemplateApprovals id of the approval this template is currently sendable under. Deliberately a raw identifier, not a relationship: TemplateApprovals already points at MessageTemplates, so declaring an FK back would make the two tables mutually dependent and the rulebook is required to stay acyclic. The value is still resolved by INDEX/MATCH in LastApprovedBodyHash.
  calc_message_templates_has_body_drifted(t.message_template_id) AS has_body_drifted,-- TRUE when the template body no longer matches what was approved.
  calc_message_templates_is_sendable_under_approval(t.message_template_id) AS is_sendable_under_approval,-- TRUE only when the template is marked Approved, has a properly-authorized approval, AND its body still matches what was approved.
  calc_message_templates_drifted_send_count(t.message_template_id) AS drifted_send_count,-- How many messages went out from this template while it was not validly sendable.
  t.semantic_type_iri                                                           -- Resource class IRI.
FROM message_templates t;

-- ----------------------------------------------------------------------------
-- vw_semantic_mappings: Machine-readable alignment from ERB table/field paths to exact PKO or reused ontology terms. Extension mappings are never presented as native PKO.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_semantic_mappings CASCADE;
CREATE VIEW vw_semantic_mappings WITH (security_invoker = ON) AS
SELECT
  t.semantic_mapping_id,                                                        -- Stored logical identifier for one SemanticMappings row.
  calc_semantic_mappings_name(t.semantic_mapping_id) AS name,                   -- Human-readable calculated display alias for the SemanticMappings row.
  t.source_path,                                                                -- ERB table, field, or discriminator path.
  t.mapping_kind,                                                               -- class, objectProperty, datatypeProperty, individual, or rule.
  t.target_iri,                                                                 -- Exact target semantic IRI.
  t.mapping_relation,                                                           -- exact, aligned, subclass, subproperty, or extension.
  t.ontology_profile,                                                           -- Versioned ontology profile containing the target term.
  t.notes                                                                       -- Mapping semantics and boundaries.
FROM semantic_mappings t;

-- ----------------------------------------------------------------------------
-- vw_witness_loops: One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop's predicates.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_witness_loops CASCADE;
CREATE VIEW vw_witness_loops WITH (security_invoker = ON) AS
SELECT
  t.witness_loop_id,                                                            -- Stored logical identifier for one WitnessLoops row.
  calc_witness_loops_name(t.witness_loop_id) AS name,                           -- Human-readable calculated display alias for the WitnessLoops row.
  t.loop_number,                                                                -- Ordinal of this expansion loop. Loop 1 is the founding set of role questions.
  t.title,                                                                      -- Short title for what this loop set out to make askable.
  t.premise,                                                                    -- Why this loop's questions became askable. For loop N>1 this names the loop N-1 predicates that made them possible.
  t.started_at,                                                                 -- Time this loop began.
  t.completed_at,                                                               -- Time this loop was committed. Null while in progress.
  calc_witness_loops_question_count(t.witness_loop_id) AS question_count,       -- How many role questions were posed in this loop.
  calc_witness_loops_is_complete(t.witness_loop_id) AS is_complete,             -- TRUE once the loop has been committed.
  t.fields_after,                                                               -- Total fields in the rulebook after this loop completed.
  t.derived_after,                                                              -- Derived fields after this loop completed.
  t.witnessed_after,                                                            -- Fields invented for a role question after this loop completed.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM witness_loops t;

-- ----------------------------------------------------------------------------
-- vw_role_questions: One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_role_questions CASCADE;
CREATE VIEW vw_role_questions WITH (security_invoker = ON) AS
SELECT
  t.role_question_id,                                                           -- Stored logical identifier for one RoleQuestions row.
  calc_role_questions_name(t.role_question_id) AS name,                         -- Human-readable calculated display alias for the RoleQuestions row.
  t.asking_role,                                                                -- The role that wants this question answered.
  t.witness_loop,                                                               -- The expansion loop in which this question was posed.
  t.question_text,                                                              -- The question in the role's own words.
  t.why_it_matters,                                                             -- What goes wrong in the real world when this question cannot be answered.
  t.answerable_before,                                                          -- TRUE if the model could already answer this before its loop ran. FALSE means the loop had to invent predicates for it.
  calc_role_questions_predicate_count(t.role_question_id) AS predicate_count,   -- How many fields were invented to answer this question.
  calc_role_questions_is_answered(t.role_question_id) AS is_answered,           -- TRUE when at least one predicate exists to answer this question.
  t.witnessed_answer,                                                           -- The current reading of this question's predicates, extracted from the substrate after the loop ran: which witness columns fire, on how many rows out of how many. Written by tools/extract_computed_answers.py from values Postgres computed — never recomputed in Python. This is what lets a later loop plan against materialized answers instead of imagined ones.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM role_questions t;

-- ----------------------------------------------------------------------------
-- vw_rulebook_fields: A complete census of every field in this rulebook. Reconciled from the real schemas by tools/reconcile_field_catalog.py — never hand-maintained. Fields invented by a witness loop carry an InventedForQuestion FK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_rulebook_fields CASCADE;
CREATE VIEW vw_rulebook_fields WITH (security_invoker = ON) AS
SELECT
  t.rulebook_field_id,                                                          -- Stored logical identifier for one RulebookFields row. Formed as <TargetTable>.<FieldName>.
  calc_rulebook_fields_name(t.rulebook_field_id) AS name,                       -- Human-readable calculated display alias for the RulebookFields row.
  t.target_table,                                                               -- The table this field lives on.
  t.field_name,                                                                 -- The field's name within its table.
  t.field_type,                                                                 -- raw, calculated, lookup, relationship, or aggregation.
  t.datatype,                                                                   -- The field's declared datatype.
  t.formula,                                                                    -- The field's formula when it is derived. Null for raw and relationship fields.
  t.invented_for_question,                                                      -- The role question that motivated this field's existence. Null for fields that predate the witness-loop exercise.
  calc_rulebook_fields_is_derived(t.rulebook_field_id) AS is_derived,           -- TRUE when this field is computed rather than stored.
  calc_rulebook_fields_is_witness(t.rulebook_field_id) AS is_witness,           -- TRUE when this field exists because a role asked a question. These are the fields the witness loops added.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM rulebook_fields t;

-- ----------------------------------------------------------------------------
-- vw_exception_invocations: ExceptionInvocations (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_exception_invocations CASCADE;
CREATE VIEW vw_exception_invocations WITH (security_invoker = ON) AS
SELECT
  t.exception_invocation_id,                                                    -- Stored logical identifier for one ExceptionInvocations row.
  calc_exception_invocations_name(t.exception_invocation_id) AS name,           -- Human-readable calculated display alias.
  t.step_execution,                                                             -- The execution during which the exception was invoked.
  t.exception,                                                                  -- The specified exception that was invoked.
  t.invoked_by_agent,                                                           -- Agent who invoked the exception.
  t.approved_by_agent,                                                          -- Agent who approved the invocation. Must satisfy the exception's ApprovalRole.
  t.invoked_at,                                                                 -- When the exception was invoked.
  t.handling_applied,                                                           -- What was actually done, in the invoker's words.
  calc_exception_invocations_expected_handling(t.exception_invocation_id) AS expected_handling,-- The handling the specification prescribes.
  calc_exception_invocations_required_approval_role(t.exception_invocation_id) AS required_approval_role,-- The role the specification requires to approve this exception.
  calc_exception_invocations_required_approval_role_holder(t.exception_invocation_id) AS required_approval_role_holder,-- The agent who currently holds the role that must approve this exception.
  calc_exception_invocations_approval_role_matches(t.exception_invocation_id) AS approval_role_matches,-- TRUE when the agent who approved is the holder of the role the exception requires.
  calc_exception_invocations_is_approved(t.exception_invocation_id) AS is_approved,-- TRUE when an approver was recorded at all.
  calc_exception_invocations_is_improperly_approved(t.exception_invocation_id) AS is_improperly_approved,-- TRUE when an exception was invoked without an approver, or approved by an agent who does not hold the required role.
  calc_exception_invocations_invoker_agent_kind(t.exception_invocation_id) AS invoker_agent_kind,-- What kind of agent invoked the exception.
  calc_exception_invocations_invoker_also_prepared_key(t.exception_invocation_id) AS invoker_also_prepared_key,-- Composite execution+approver key, in the same key space as StepExecutions.PreparerAgentKey.
  calc_exception_invocations_parent_procedure_execution(t.exception_invocation_id) AS parent_procedure_execution,-- The procedure execution this invocation belongs to.
  calc_exception_invocations_approver_prepared_count(t.exception_invocation_id) AS approver_prepared_count,-- How many preparation steps in the same execution were run by the agent who approved this exception.
  calc_exception_invocations_delegated_to_preparer(t.exception_invocation_id) AS delegated_to_preparer,-- TRUE when an exception routed approval authority to an agent who prepared work in the same execution.
  calc_exception_invocations_is_ungoverned_invocation(t.exception_invocation_id) AS is_ungoverned_invocation,-- TRUE when an exception was invoked without proper role authority, or routed authority to the preparer.
  t.semantic_type_iri                                                           -- Extension IRI — PKO does not define exception invocation.
FROM exception_invocations t;

-- ----------------------------------------------------------------------------
-- vw_verification_outcomes: VerificationOutcomes (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_verification_outcomes CASCADE;
CREATE VIEW vw_verification_outcomes WITH (security_invoker = ON) AS
SELECT
  t.verification_outcome_id,                                                    -- Stored logical identifier for one VerificationOutcomes row.
  calc_verification_outcomes_name(t.verification_outcome_id) AS name,           -- Human-readable calculated display alias.
  t.step_execution,                                                             -- The execution during which the verification was performed.
  t.step_verification,                                                          -- The declared verification being performed.
  t.observed_signal_value,                                                      -- The value the signal actually read at verification time.
  t.observed_by_agent,                                                          -- Agent who observed the signal.
  t.observed_at,                                                                -- When the signal was observed.
  t.evidence_uri,                                                               -- Pointer to the retained artifact backing the observation.
  calc_verification_outcomes_expected_signal_value(t.verification_outcome_id) AS expected_signal_value,-- The value the specification expects.
  calc_verification_outcomes_signal_identifier(t.verification_outcome_id) AS signal_identifier,-- Which signal this outcome concerns.
  calc_verification_outcomes_signal_matches_expected(t.verification_outcome_id) AS signal_matches_expected,-- TRUE when the observed value equals the expected value.
  calc_verification_outcomes_has_evidence(t.verification_outcome_id) AS has_evidence,-- TRUE when a retained artifact backs this observation.
  calc_verification_outcomes_is_unbacked_observation(t.verification_outcome_id) AS is_unbacked_observation,-- TRUE when a verification was recorded as matching but no evidence artifact was retained.
  calc_verification_outcomes_is_self_witnessed(t.verification_outcome_id) AS is_self_witnessed,-- TRUE when the agent who observed the verification signal is the same agent who executed the step being verified.
  calc_verification_outcomes_step_executor_agent(t.verification_outcome_id) AS step_executor_agent,-- The agent who executed the step this verification outcome concerns.
  calc_verification_outcomes_self_witnessed_step_key(t.verification_outcome_id) AS self_witnessed_step_key,-- Echoes the StepExecution id only for self-witnessed verifications.
  calc_verification_outcomes_unbacked_step_key(t.verification_outcome_id) AS unbacked_step_key,-- Echoes the StepExecution id when a verification matched but retained no evidence.
  t.semantic_type_iri                                                           -- Extension IRI — PKO 2.0.0 has no execution-side verification outcome class.
FROM verification_outcomes t;

-- ----------------------------------------------------------------------------
-- vw_observed_transitions: The proxy above cannot tell a walked fallback from a happy-path step that happens to share an endpoint. PKO models Transition as a first-class thing; its execution counterpart is missing. Without a table that records WHICH transition a step execution arrived by, 'has this fallback ever been walked' is permanently unanswerable rather than merely unanswered. This is an extension (urn:effortless:pko-extension#ObservedTransition), not a native PKO term.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_observed_transitions CASCADE;
CREATE VIEW vw_observed_transitions WITH (security_invoker = ON) AS
SELECT
  t.observed_transition_id,                                                     -- Stored logical identifier for one ObservedTransitions row.
  calc_observed_transitions_name(t.observed_transition_id) AS name,             -- Human-readable calculated display alias.
  t.procedure_execution,                                                        -- The procedure execution during which this transition was traversed.
  t.step_transition,                                                            -- The specification-level transition that was actually taken.
  t.arriving_step_execution,                                                    -- The step execution that this traversal produced.
  t.observed_at,                                                                -- When the traversal occurred.
  t.trigger_reason,                                                             -- Why this path rather than the default was taken.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM observed_transitions t;

-- ----------------------------------------------------------------------------
-- vw_recipients: Recipients (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_recipients CASCADE;
CREATE VIEW vw_recipients WITH (security_invoker = ON) AS
SELECT
  t.recipient_id,                                                               -- Stored logical identifier for one Recipients row.
  calc_recipients_name(t.recipient_id) AS name,                                 -- Human-readable calculated display alias for the Recipients row.
  t.display_name,                                                               -- Employee display name as carried in the consent registry.
  t.organization,                                                               -- Organization the recipient belongs to.
  t.email_address,                                                              -- Corporate email address; empty string when the recipient has no valid corporate email.
  t.mobile_number,                                                              -- Mobile number in E.164 form; empty string when no mobile number is on file.
  t.sms_consent_status,                                                         -- Consent state as observed in the consent registry: Granted, Revoked, or NeverGiven.
  t.sms_consent_at,                                                             -- Timestamp at which the current SMS consent state took effect.
  t.consent_binding,                                                            -- Operational binding through which this consent state was observed.
  calc_recipients_has_sms_consent(t.recipient_id) AS has_sms_consent,           -- TRUE only when the recipient's SMS consent state is Granted.
  calc_recipients_is_email_reachable(t.recipient_id) AS is_email_reachable,     -- TRUE when a corporate email address is on file for this recipient.
  calc_recipients_is_sms_reachable(t.recipient_id) AS is_sms_reachable,         -- TRUE when a mobile number is on file for this recipient.
  calc_recipients_is_unreachable(t.recipient_id) AS is_unreachable,             -- TRUE when the recipient has neither an email address nor a mobile number -- the exc-unreachable trigger condition.
  t.semantic_type_iri                                                           -- Extension IRI; recipients are not a PKO 2.0.0 native class.
FROM recipients t;

-- ----------------------------------------------------------------------------
-- vw_message_deliveries: MessageDeliveries (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_message_deliveries CASCADE;
CREATE VIEW vw_message_deliveries WITH (security_invoker = ON) AS
SELECT
  t.message_delivery_id,                                                        -- Stored logical identifier for one MessageDeliveries row.
  calc_message_deliveries_name(t.message_delivery_id) AS name,                  -- Human-readable calculated display alias for the MessageDeliveries row.
  t.procedure_execution,                                                        -- The procedure execution this send was performed under.
  t.step_execution,                                                             -- The step execution that performed the send.
  t.recipient,                                                                  -- Who the message was sent to.
  t.message_template,                                                           -- Template that was rendered for this send.
  t.sent_by_agent,                                                              -- Agent that performed the send.
  t.rendered_body,                                                              -- The exact body text that was transmitted, after variable substitution.
  t.sent_at,                                                                    -- Transmission timestamp.
  t.sent_at_local_hour,                                                         -- Hour of day 0-23 in the RECIPIENT's local timezone at transmission. Stored raw because recipient-local time is what the quiet-hours rule is written against and it is not derivable from SentAt alone.
  t.delivery_status,                                                            -- Sent, Delivered, Failed, Suppressed, or Bounced.
  t.suppression_reason,                                                         -- When DeliveryStatus is Suppressed, why; empty string otherwise.
  t.invoked_exception,                                                          -- Documented exception invoked for this delivery, when one was.
  t.acknowledged_at,                                                            -- When the recipient acknowledged; null when not acknowledged.
  calc_message_deliveries_policy_channel(t.message_delivery_id) AS policy_channel,-- The communication policy governing the template that was sent.
  calc_message_deliveries_channel_name(t.message_delivery_id) AS channel_name,  -- Channel (Email, SMS) of the policy this delivery went out under.
  calc_message_deliveries_policy_requires_consent(t.message_delivery_id) AS policy_requires_consent,-- Whether the governing policy requires active consent for this channel.
  calc_message_deliveries_recipient_has_sms_consent(t.message_delivery_id) AS recipient_has_sms_consent,-- Whether the recipient of this delivery had SMS consent on file.
  calc_message_deliveries_was_actually_transmitted(t.message_delivery_id) AS was_actually_transmitted,-- TRUE when the message actually left our systems. Suppressed and Failed messages never reached the carrier.
  calc_message_deliveries_is_consent_violation(t.message_delivery_id) AS is_consent_violation,-- TRUE when a message was actually transmitted on a consent-required channel to a recipient without consent. This is the TCPA witness.
  calc_message_deliveries_consent_violation_policy_key(t.message_delivery_id) AS consent_violation_policy_key,-- Carries the policy id only on rows that are consent violations; empty string otherwise.
  calc_message_deliveries_policy_quiet_hours_start_hour(t.message_delivery_id) AS policy_quiet_hours_start_hour,-- Quiet-hours start hour (0-23) from the governing policy.
  calc_message_deliveries_policy_quiet_hours_end_hour(t.message_delivery_id) AS policy_quiet_hours_end_hour,-- Quiet-hours end hour (0-23) from the governing policy.
  calc_message_deliveries_policy_has_quiet_hours(t.message_delivery_id) AS policy_has_quiet_hours,-- TRUE when the governing policy actually declares a quiet-hours window. comm-email-policy has 00:00-00:00, meaning no window.
  calc_message_deliveries_quiet_window_wraps_midnight(t.message_delivery_id) AS quiet_window_wraps_midnight,-- TRUE when the quiet window crosses midnight (20:00 -> 08:00 does).
  calc_message_deliveries_is_inside_quiet_window(t.message_delivery_id) AS is_inside_quiet_window,-- TRUE when the recipient-local send hour falls inside the declared quiet window, handling the midnight wrap correctly.
  calc_message_deliveries_is_quiet_hours_violation(t.message_delivery_id) AS is_quiet_hours_violation,-- TRUE when a message was actually transmitted inside a declared quiet-hours window. The quiet-hours witness.
  calc_message_deliveries_quiet_hours_violation_policy_key(t.message_delivery_id) AS quiet_hours_violation_policy_key,-- Carries the policy id only on quiet-hours violations; empty string otherwise.
  calc_message_deliveries_recipient_is_unreachable(t.message_delivery_id) AS recipient_is_unreachable,-- Whether the recipient has neither email nor mobile on file -- the exc-unreachable trigger.
  calc_message_deliveries_is_acknowledged(t.message_delivery_id) AS is_acknowledged,-- TRUE when an acknowledgement timestamp is recorded for this delivery.
  calc_message_deliveries_invoked_exception_condition(t.message_delivery_id) AS invoked_exception_condition,-- The documented condition of the exception invoked on this delivery, if any.
  calc_message_deliveries_has_unreachable_exception_invoked(t.message_delivery_id) AS has_unreachable_exception_invoked,-- TRUE when the documented unreachable-recipient exception was formally invoked on this delivery.
  calc_message_deliveries_is_fabricated_acknowledgement(t.message_delivery_id) AS is_fabricated_acknowledgement,-- TRUE when an acknowledgement is recorded for a recipient we could not reach. This is the misrepresentation witness.
  calc_message_deliveries_is_unhandled_unreachable(t.message_delivery_id) AS is_unhandled_unreachable,-- TRUE when a recipient was unreachable but no documented exception was invoked -- the case fell on the floor silently.
  calc_message_deliveries_unreachable_failure_key(t.message_delivery_id) AS unreachable_failure_key,-- Carries the execution id on any unreachable-handling failure; empty string otherwise.
  calc_message_deliveries_policy_retention_days(t.message_delivery_id) AS policy_retention_days,-- Retention commitment in days inherited from the governing channel policy.
  calc_message_deliveries_age_days(t.message_delivery_id) AS age_days,          -- Days elapsed since transmission.
  calc_message_deliveries_is_within_retention_window(t.message_delivery_id) AS is_within_retention_window,-- TRUE while this delivery is still inside its committed retention period.
  calc_message_deliveries_has_rendered_body(t.message_delivery_id) AS has_rendered_body,-- TRUE when the exact transmitted text is still held on this record.
  calc_message_deliveries_is_evidence_required(t.message_delivery_id) AS is_evidence_required,-- TRUE when we are still obliged to hold this message's text.
  calc_message_deliveries_is_retention_breach(t.message_delivery_id) AS is_retention_breach,-- TRUE when we are obliged to hold the message text and do not. The evidentiary-gap witness.
  calc_message_deliveries_retention_breach_execution_key(t.message_delivery_id) AS retention_breach_execution_key,-- Carries the execution id on retention breaches; empty string otherwise.
  calc_message_deliveries_sending_step_execution_step(t.message_delivery_id) AS sending_step_execution_step,-- Which procedure step this delivery was performed under.
  calc_message_deliveries_execution_has_cleared_legal_review(t.message_delivery_id) AS execution_has_cleared_legal_review,-- Whether legal review had passed for the execution this delivery belongs to.
  calc_message_deliveries_is_unreviewed_send(t.message_delivery_id) AS is_unreviewed_send,-- TRUE when a message was transmitted under an execution whose legal review had not passed. The ungated-send witness.
  calc_message_deliveries_rendered_body_length(t.message_delivery_id) AS rendered_body_length,-- Character length of the exact text that was actually transmitted.
  calc_message_deliveries_policy_max_message_length_at_send(t.message_delivery_id) AS policy_max_message_length_at_send,-- The per-segment limit that governed this specific send.
  calc_message_deliveries_segment_count(t.message_delivery_id) AS segment_count,-- How many channel segments the transmitted text occupied.
  calc_message_deliveries_policy_max_segments_at_send(t.message_delivery_id) AS policy_max_segments_at_send,-- The segment ceiling that governed this specific send.
  calc_message_deliveries_is_over_segment_limit(t.message_delivery_id) AS is_over_segment_limit,-- TRUE when a transmitted message split into more segments than the policy permits. The oversize witness.
  calc_message_deliveries_template_has_valid_approval(t.message_delivery_id) AS template_has_valid_approval,-- Whether the template used for this delivery had a properly-authorized approval.
  calc_message_deliveries_is_unapproved_send(t.message_delivery_id) AS is_unapproved_send,-- TRUE when a message was transmitted using a template with no valid approval behind it.
  calc_message_deliveries_policy_required_opt_out_phrase(t.message_delivery_id) AS policy_required_opt_out_phrase,-- The opt-out phrase required for this delivery's channel.
  calc_message_deliveries_policy_requires_opt_out(t.message_delivery_id) AS policy_requires_opt_out,-- TRUE when the governing channel policy declares a required opt-out phrase at all.
  calc_message_deliveries_opt_out_phrase_position(t.message_delivery_id) AS opt_out_phrase_position,-- Character position at which the required opt-out phrase appears in the transmitted text; 0 when absent.
  calc_message_deliveries_has_opt_out_phrase(t.message_delivery_id) AS has_opt_out_phrase,-- TRUE when the required opt-out phrase appears anywhere in the transmitted text.
  calc_message_deliveries_is_opt_out_in_first_segment(t.message_delivery_id) AS is_opt_out_in_first_segment,-- TRUE when the opt-out phrase falls inside the first segment, where it is guaranteed to be read.
  calc_message_deliveries_is_missing_required_opt_out(t.message_delivery_id) AS is_missing_required_opt_out,-- TRUE when a transmitted message on an opt-out-required channel did not contain the phrase at all. The hard witness.
  calc_message_deliveries_is_opt_out_at_risk_of_truncation(t.message_delivery_id) AS is_opt_out_at_risk_of_truncation,-- TRUE when the opt-out phrase is present but sits beyond the first segment, where carrier truncation or out-of-order delivery can hide it. The soft witness.
  calc_message_deliveries_is_failed_delivery(t.message_delivery_id) AS is_failed_delivery,-- TRUE when the message left our systems but did not land.
  calc_message_deliveries_is_suppressed(t.message_delivery_id) AS is_suppressed,-- TRUE when we deliberately chose not to transmit.
  calc_message_deliveries_is_triaged(t.message_delivery_id) AS is_triaged,      -- TRUE when some documented exception was formally invoked on this delivery -- i.e. a human or a rule picked it up.
  calc_message_deliveries_is_abandoned_failure(t.message_delivery_id) AS is_abandoned_failure,-- TRUE when a delivery failed and no documented exception was invoked. The abandoned-bounce witness.
  calc_message_deliveries_abandoned_failure_execution_key(t.message_delivery_id) AS abandoned_failure_execution_key,-- Carries the execution id on abandoned failures; empty string otherwise.
  calc_message_deliveries_reached_execution_key(t.message_delivery_id) AS reached_execution_key,-- Carries the execution id on confirmed-delivered messages; empty string otherwise.
  calc_message_deliveries_template_was_sendable(t.message_delivery_id) AS template_was_sendable,-- Whether the template used for this delivery was fully sendable under a current, matching approval.
  calc_message_deliveries_is_drifted_send(t.message_delivery_id) AS is_drifted_send,-- TRUE when a message was transmitted from a template that was not validly sendable at the time. The drift witness.
  calc_message_deliveries_drifted_send_template_key(t.message_delivery_id) AS drifted_send_template_key,-- Carries the template id on drifted sends; empty string otherwise.
  t.semantic_type_iri                                                           -- Extension IRI; per-recipient delivery events are not a PKO 2.0.0 native class.
FROM message_deliveries t;

-- ----------------------------------------------------------------------------
-- vw_template_approvals: TemplateApprovals (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_template_approvals CASCADE;
CREATE VIEW vw_template_approvals WITH (security_invoker = ON) AS
SELECT
  t.template_approval_id,                                                       -- Stored logical identifier for one TemplateApprovals row.
  calc_template_approvals_name(t.template_approval_id) AS name,                 -- Human-readable calculated display alias for the TemplateApprovals row.
  t.message_template,                                                           -- Template this decision applies to.
  t.decided_by_agent,                                                           -- Agent who made the approval decision.
  t.decided_in_role,                                                            -- Role the agent was acting in when deciding.
  t.decision,                                                                   -- Approved, Rejected, or Withdrawn.
  t.decided_at,                                                                 -- When the decision was recorded.
  t.approved_body_hash,                                                         -- Digest of the exact template body that was approved, so later edits are detectable.
  t.notes,                                                                      -- Approver's rationale or conditions.
  calc_template_approvals_is_approval_decision(t.template_approval_id) AS is_approval_decision,-- TRUE when this decision row is an approval rather than a rejection or withdrawal.
  calc_template_approvals_template_policy(t.template_approval_id) AS template_policy,-- The communication policy governing the template being approved.
  calc_template_approvals_required_approval_role(t.template_approval_id) AS required_approval_role,-- The role the governing policy designates as approver -- communications-manager for both current policies.
  calc_template_approvals_is_decided_by_required_role(t.template_approval_id) AS is_decided_by_required_role,-- TRUE when the approving role matches the role the policy designates.
  calc_template_approvals_valid_approval_template_key(t.template_approval_id) AS valid_approval_template_key,-- Carries the template id only on approvals made by the correct role; empty string otherwise.
  t.semantic_type_iri                                                           -- Extension IRI; template approval events are not a PKO 2.0.0 native class.
FROM template_approvals t;

-- ----------------------------------------------------------------------------
-- vw_send_intents: SendIntents (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_send_intents CASCADE;
CREATE VIEW vw_send_intents WITH (security_invoker = ON) AS
SELECT
  t.send_intent_id,                                                             -- Stored logical identifier for one SendIntents row.
  calc_send_intents_name(t.send_intent_id) AS name,                             -- Human-readable calculated display alias for the SendIntents row.
  t.procedure_execution,                                                        -- Execution this send intent belongs to.
  t.step_execution,                                                             -- Step execution evaluating this intent.
  t.recipient,                                                                  -- Intended recipient.
  t.message_template,                                                           -- Template the pipeline intends to render and send.
  t.proposed_body,                                                              -- The fully rendered text the pipeline intends to transmit, before transmission.
  t.proposed_send_at_local_hour,                                                -- Hour 0-23 in the recipient's local timezone at which the pipeline intends to transmit.
  t.evaluated_at,                                                               -- When the pipeline evaluated the gates for this intent.
  t.resulting_delivery,                                                         -- The delivery record produced from this intent, whether transmitted or suppressed.
  calc_send_intents_intent_policy(t.send_intent_id) AS intent_policy,           -- The communication policy governing the template this intent would send.
  calc_send_intents_intent_channel(t.send_intent_id) AS intent_channel,         -- Channel this intent would transmit on.
  calc_send_intents_policy_is_active(t.send_intent_id) AS policy_is_active,     -- Whether the governing policy is currently Active rather than Draft, Suspended, or Retired.
  calc_send_intents_intent_requires_consent(t.send_intent_id) AS intent_requires_consent,-- Whether the governing policy requires consent for this channel.
  calc_send_intents_recipient_has_channel_consent(t.send_intent_id) AS recipient_has_channel_consent,-- Whether the intended recipient has active SMS consent on record.
  calc_send_intents_consent_gate_passed(t.send_intent_id) AS consent_gate_passed,-- TRUE when either the channel does not require consent, or the recipient has granted it.
  calc_send_intents_recipient_is_sms_reachable(t.send_intent_id) AS recipient_is_sms_reachable,-- Whether a mobile number is on file for the intended recipient.
  calc_send_intents_recipient_is_email_reachable(t.send_intent_id) AS recipient_is_email_reachable,-- Whether an email address is on file for the intended recipient.
  calc_send_intents_reachability_gate_passed(t.send_intent_id) AS reachability_gate_passed,-- TRUE when the recipient is reachable on the channel this intent would use.
  calc_send_intents_permission_gate_passed(t.send_intent_id) AS permission_gate_passed,-- TRUE when the policy is active, consent is satisfied, and the recipient is reachable on this channel. The channel-permission gate.
  calc_send_intents_intent_quiet_start_hour(t.send_intent_id) AS intent_quiet_start_hour,-- Quiet-hours start hour from the governing policy.
  calc_send_intents_intent_quiet_end_hour(t.send_intent_id) AS intent_quiet_end_hour,-- Quiet-hours end hour from the governing policy.
  calc_send_intents_intent_policy_has_quiet_hours(t.send_intent_id) AS intent_policy_has_quiet_hours,-- TRUE when the governing policy declares a real quiet-hours window.
  calc_send_intents_intent_quiet_window_wraps(t.send_intent_id) AS intent_quiet_window_wraps,-- TRUE when the quiet window crosses midnight.
  calc_send_intents_intent_is_inside_quiet_window(t.send_intent_id) AS intent_is_inside_quiet_window,-- TRUE when the proposed recipient-local send hour falls inside the forbidden window.
  calc_send_intents_timing_gate_passed(t.send_intent_id) AS timing_gate_passed, -- TRUE when transmitting now is permitted on timing grounds. The timing gate.
  calc_send_intents_hours_until_window_opens(t.send_intent_id) AS hours_until_window_opens,-- How many hours the pipeline must defer before transmission becomes permitted; 0 when already permitted.
  calc_send_intents_intent_max_message_length(t.send_intent_id) AS intent_max_message_length,-- Per-segment character limit from the governing policy.
  calc_send_intents_intent_max_segments(t.send_intent_id) AS intent_max_segments,-- Segment ceiling from the governing policy.
  t.proposed_body_length,                                                       -- Character count of ProposedBody, written by the pipeline at render time.
  t.proposed_segment_count,                                                     -- Number of channel segments ProposedBody will occupy, computed by the pipeline at render time.
  calc_send_intents_length_gate_passed(t.send_intent_id) AS length_gate_passed, -- TRUE when the proposed text is non-empty and fits within the segment ceiling.
  calc_send_intents_intent_required_opt_out_phrase(t.send_intent_id) AS intent_required_opt_out_phrase,-- Opt-out phrase the governing policy requires in every message on this channel.
  t.proposed_opt_out_position,                                                  -- Character position of the required opt-out phrase within ProposedBody; 0 when absent. Written by the pipeline at render time.
  calc_send_intents_opt_out_gate_passed(t.send_intent_id) AS opt_out_gate_passed,-- TRUE when no opt-out is required, or the required phrase is present within the first segment.
  calc_send_intents_content_gate_passed(t.send_intent_id) AS content_gate_passed,-- TRUE when the proposed text satisfies every content rule of the governing channel policy.
  calc_send_intents_template_is_sendable(t.send_intent_id) AS template_is_sendable,-- Whether the template carries a current, properly-authorized, non-drifted approval.
  calc_send_intents_execution_has_legal_clearance(t.send_intent_id) AS execution_has_legal_clearance,-- Whether legal review has passed for the execution this intent belongs to.
  calc_send_intents_intent_approval_role(t.send_intent_id) AS intent_approval_role,-- The role the governing policy designates as the approving authority.
  calc_send_intents_approval_role_agent_kind(t.send_intent_id) AS approval_role_agent_kind,-- Whether the agent currently filling the designated approval role is Human, AIAgent, or AutomatedPipeline.
  calc_send_intents_approval_is_human(t.send_intent_id) AS approval_is_human,   -- TRUE when the designated approval role is currently held by a human agent.
  calc_send_intents_authorization_gate_passed(t.send_intent_id) AS authorization_gate_passed,-- TRUE only when the template is validly approved, legal review has cleared, and the approving role is held by a human. The authorization gate.
  calc_send_intents_is_cleared_to_send(t.send_intent_id) AS is_cleared_to_send, -- TRUE only when all four gates pass. THE single column the pipeline reads before transmitting.
  calc_send_intents_blocking_gate_name(t.send_intent_id) AS blocking_gate_name, -- Names the first gate that refused, for the suppression reason; empty string when cleared.
  calc_send_intents_has_resulting_delivery(t.send_intent_id) AS has_resulting_delivery,-- TRUE when this intent produced a delivery record of any status.
  calc_send_intents_resulting_delivery_was_transmitted(t.send_intent_id) AS resulting_delivery_was_transmitted,-- Whether the delivery produced from this intent actually left our systems.
  calc_send_intents_is_overridden_refusal(t.send_intent_id) AS is_overridden_refusal,-- TRUE when a gate refused and the message was transmitted regardless. The override witness.
  calc_send_intents_is_silently_dropped(t.send_intent_id) AS is_silently_dropped,-- TRUE when a gate refused and no delivery record of any kind was produced -- the recipient vanished from the run.
  calc_send_intents_resulting_delivery_exception(t.send_intent_id) AS resulting_delivery_exception,-- The documented exception invoked on the delivery produced from this intent, if any.
  calc_send_intents_refusal_cited_an_exception(t.send_intent_id) AS refusal_cited_an_exception,-- TRUE when the suppression produced by this refusal cited a documented exception.
  calc_send_intents_is_properly_handled_refusal(t.send_intent_id) AS is_properly_handled_refusal,-- TRUE when a refusal correctly resulted in a non-transmitted delivery record citing a documented exception. The positive witness.
  calc_send_intents_refusal_failure_execution_key(t.send_intent_id) AS refusal_failure_execution_key,-- Carries the execution id on any mishandled refusal; empty string otherwise.
  t.semantic_type_iri                                                           -- Extension IRI; pre-send intents are not a PKO 2.0.0 native class.
FROM send_intents t;

-- ----------------------------------------------------------------------------
-- vw_agent_decision_records: AgentDecisionRecords (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_agent_decision_records CASCADE;
CREATE VIEW vw_agent_decision_records WITH (security_invoker = ON) AS
SELECT
  t.agent_decision_record_id,                                                   -- Stored logical identifier for one AgentDecisionRecords row.
  calc_agent_decision_records_name(t.agent_decision_record_id) AS name,         -- Human-readable calculated display alias for the AgentDecisionRecords row.
  t.step_execution,                                                             -- Step execution during which the decision was made.
  t.deciding_agent,                                                             -- Agent that made the decision.
  t.decision_kind,                                                              -- Classification, Prioritization, Draft, Suppression, Escalation, or Posting.
  t.decision_summary,                                                           -- What the agent decided, in one sentence.
  t.decided_at,                                                                 -- When the decision was made.
  t.materiality_band,                                                           -- BelowThreshold, Material, or Escalated.
  t.human_disposition,                                                          -- Accepted, Corrected, Reversed, or NotReviewed.
  t.reviewed_by_agent,                                                          -- Human agent that dispositioned the decision.
  t.reviewed_at,                                                                -- When a human dispositioned the decision.
  calc_agent_decision_records_was_overridden(t.agent_decision_record_id) AS was_overridden,-- TRUE when a human corrected or reversed this decision.
  calc_agent_decision_records_was_reviewed(t.agent_decision_record_id) AS was_reviewed,-- TRUE when a human actually dispositioned this decision.
  calc_agent_decision_records_deciding_agent_kind(t.agent_decision_record_id) AS deciding_agent_kind,-- Whether the deciding agent is Human, AIAgent, or AutomatedPipeline.
  calc_agent_decision_records_deciding_agent_when_overridden(t.agent_decision_record_id) AS deciding_agent_when_overridden,-- Echoes the deciding agent id when the decision was overridden, blank otherwise.
  t.under_role_assignment,                                                      -- Role assignment in force when the decision was made; anchors the decision to one side of a handover.
  calc_agent_decision_records_role_assignment_when_scored(t.agent_decision_record_id) AS role_assignment_when_scored,-- Echoes the governing role assignment when one is recorded, blank otherwise.
  calc_agent_decision_records_role_assignment_when_overridden(t.agent_decision_record_id) AS role_assignment_when_overridden,-- Echoes the governing role assignment when the decision was overridden, blank otherwise.
  calc_agent_decision_records_step_of_decision(t.agent_decision_record_id) AS step_of_decision,-- The specified step at which this decision was made.
  calc_agent_decision_records_boundary_match_key(t.agent_decision_record_id) AS boundary_match_key,-- Composite key of step, deciding agent kind, and decision kind for this decision.
  calc_agent_decision_records_matching_boundary_count(t.agent_decision_record_id) AS matching_boundary_count,-- Number of authority boundaries this decision matches.
  calc_agent_decision_records_violated_authority_boundary(t.agent_decision_record_id) AS violated_authority_boundary,-- TRUE when this decision matches an authority boundary that forbids it.
  calc_agent_decision_records_reviewer_agent_kind(t.agent_decision_record_id) AS reviewer_agent_kind,-- Agent kind of the reviewer, if any.
  calc_agent_decision_records_has_human_confirmation(t.agent_decision_record_id) AS has_human_confirmation,-- TRUE when a human agent actually dispositioned this decision.
  calc_agent_decision_records_needs_human_confirmation(t.agent_decision_record_id) AS needs_human_confirmation,-- TRUE when a non-human agent made a material or escalated decision.
  calc_agent_decision_records_is_unconfirmed_non_human_decision(t.agent_decision_record_id) AS is_unconfirmed_non_human_decision,-- TRUE when a material non-human decision was never confirmed by a human.
  calc_agent_decision_records_step_execution_when_unconfirmed(t.agent_decision_record_id) AS step_execution_when_unconfirmed,-- Echoes the step-execution id when the decision is an unconfirmed non-human material decision, blank otherwise.
  calc_agent_decision_records_agent_when_boundary_violated(t.agent_decision_record_id) AS agent_when_boundary_violated,-- Echoes the deciding agent id when the decision violated a boundary, blank otherwise.
  calc_agent_decision_records_review_latency_minutes(t.agent_decision_record_id) AS review_latency_minutes,-- Minutes between the decision and its human disposition; 0 when never reviewed.
  calc_agent_decision_records_is_draft_kind(t.agent_decision_record_id) AS is_draft_kind,-- TRUE when this decision produced text — the drafter's own output class.
  calc_agent_decision_records_agent_when_draft_overridden(t.agent_decision_record_id) AS agent_when_draft_overridden,-- Echoes the deciding agent id when a drafting decision was overridden, blank otherwise.
  calc_agent_decision_records_agent_when_draft(t.agent_decision_record_id) AS agent_when_draft,-- Echoes the deciding agent id when the decision produced text, blank otherwise.
  t.semantic_type_iri                                                           -- Extension class IRI for an agent decision record.
FROM agent_decision_records t;

-- ----------------------------------------------------------------------------
-- vw_delivered_communications: Everything above is a proxy for the real question, which is instance-level: THIS message, to THIS recipient, rendered from THIS template, authorized by THIS approval. The model has MessageTemplates and CommunicationPolicies as specifications and no record of a single thing ever sent. Without an instance table, 'can I show that what was sent matched what I approved' is permanently unanswerable rather than merely unanswered — and it is the question a disputing employee actually asks. Extension term (urn:effortless:pko-extension#DeliveredCommunication); PKO has no native class for a delivered artifact instance.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_delivered_communications CASCADE;
CREATE VIEW vw_delivered_communications WITH (security_invoker = ON) AS
SELECT
  t.delivered_communication_id,                                                 -- Stored logical identifier for one DeliveredCommunications row.
  calc_delivered_communications_name(t.delivered_communication_id) AS name,     -- Human-readable calculated display alias.
  t.procedure_execution,                                                        -- The run that produced this delivery.
  t.sending_step_execution,                                                     -- The policy-07 step execution that sent it.
  t.authorizing_step_execution,                                                 -- The human approval gate execution that authorized this content. Null means nobody approved it.
  t.message_template,                                                           -- The approved template this delivery was rendered from.
  t.channel,                                                                    -- Email or SMS.
  t.recipient_key,                                                              -- Opaque recipient identifier; no personal data in the rulebook.
  t.sent_at,                                                                    -- When the message was dispatched.
  t.rendered_content_hash,                                                      -- Hash of the exact bytes delivered, for comparison against the approved rendering.
  t.approved_content_hash,                                                      -- Hash of the content as it stood at the approval gate.
  t.delivery_status,                                                            -- Provider-reported delivery outcome.
  t.semantic_type_iri,                                                          -- Extension class IRI.
  calc_delivered_communications_has_authorization(t.delivered_communication_id) AS has_authorization,-- TRUE when this delivery names the approval that authorized it.
  calc_delivered_communications_content_matches_approval(t.delivered_communication_id) AS content_matches_approval,-- TRUE when the bytes delivered are the bytes approved.
  calc_delivered_communications_authorized_at(t.delivered_communication_id) AS authorized_at,-- When the authorizing approval completed.
  calc_delivered_communications_was_approved_before_sending(t.delivered_communication_id) AS was_approved_before_sending,-- TRUE when the approval preceded the send.
  calc_delivered_communications_is_defensible(t.delivered_communication_id) AS is_defensible-- TRUE when this delivery can be defended in a dispute: authorized, unaltered, and approved beforehand.
FROM delivered_communications t;

-- ----------------------------------------------------------------------------
-- vw_authority_boundaries: AuthorityBoundaries (added by witness loop 1).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_authority_boundaries CASCADE;
CREATE VIEW vw_authority_boundaries WITH (security_invoker = ON) AS
SELECT
  t.authority_boundary_id,                                                      -- Stored logical identifier for one AuthorityBoundaries row.
  calc_authority_boundaries_name(t.authority_boundary_id) AS name,              -- Human-readable calculated display alias for the AuthorityBoundaries row.
  t.step,                                                                       -- Step at which the boundary applies.
  t.forbidden_agent_kind,                                                       -- Agent kind that may not perform the forbidden decision kind: Human, AIAgent, or AutomatedPipeline.
  t.forbidden_decision_kind,                                                    -- Decision kind forbidden to that agent kind at this step.
  t.ratified_by_knowledge_fragment,                                             -- Knowledge fragment that states the boundary.
  t.enforcing_requirement,                                                      -- Requirement under which the boundary is enforced, if any.
  t.authority_role,                                                             -- Role accountable for the boundary.
  t.valid_from,                                                                 -- Start of the boundary's valid-time interval.
  t.valid_to,                                                                   -- End of the boundary's valid-time interval; null means open-ended.
  t.status,                                                                     -- Approved, Proposed, or Retired.
  calc_authority_boundaries_is_currently_binding(t.authority_boundary_id) AS is_currently_binding,-- TRUE when this boundary is approved and inside its valid-time window right now.
  calc_authority_boundaries_ratifying_fragment_is_valid(t.authority_boundary_id) AS ratifying_fragment_is_valid,-- Whether the knowledge fragment that ratified this boundary is still valid.
  calc_authority_boundaries_step_when_binding(t.authority_boundary_id) AS step_when_binding,-- Echoes the step id when this boundary is currently binding, blank otherwise.
  calc_authority_boundaries_boundary_match_key(t.authority_boundary_id) AS boundary_match_key,-- Composite key of step, forbidden agent kind, and forbidden decision kind.
  calc_authority_boundaries_violation_count(t.authority_boundary_id) AS violation_count,-- Number of recorded decisions that this boundary forbids.
  calc_authority_boundaries_is_untested(t.authority_boundary_id) AS is_untested,-- TRUE when a binding boundary has never been triggered by any recorded decision.
  t.semantic_type_iri                                                           -- Extension class IRI for an authority boundary.
FROM authority_boundaries t;

